import { GoogleGenAI, Type } from "@google/genai";
import { SuggestionResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeScript = async (input: string): Promise<SuggestionResponse> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this video script/description and suggest high-converting thumbnail elements: "${input}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          titles: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3-5 Short, punchy, click-worthy titles (max 6 words each)."
          },
          imagePrompts: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "2-3 highly descriptive prompts for generating a background image."
          }
        },
        required: ["titles", "imagePrompts"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{}') as SuggestionResponse;
  } catch (e) {
    throw new Error("Failed to parse AI response");
  }
};

export const generateThumbnailImage = async (prompt: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { text: `High quality cinematic youtube thumbnail background, professional lighting, no text, no logos: ${prompt}` }
      ]
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (part?.inlineData) {
    return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
  }

  throw new Error("No image generated");
};

