import React, { useState, useCallback } from 'react';
import { AppStatus, SuggestionResponse, ThumbnailConfig } from './types';
import { DEFAULT_CONFIG } from './constants';
import { analyzeScript, generateThumbnailImage } from './services/geminiService';
import { EditorControls } from './components/EditorControls';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [script, setScript] = useState('');
  const [suggestions, setSuggestions] = useState<SuggestionResponse | null>(null);
  const [config, setConfig] = useState<ThumbnailConfig>(DEFAULT_CONFIG);
  const [error, setError] = useState<string | null>(null);

  const handleAnalyze = async () => {
    if (!script.trim()) return;
    setStatus(AppStatus.ANALYZING);
    setError(null);
    try {
      const result = await analyzeScript(script);
      setSuggestions(result);
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to analyze script. Please try again.');
      setStatus(AppStatus.IDLE);
    }
  };

  const handleGenerateImage = async (prompt: string) => {
    setStatus(AppStatus.GENERATING_IMAGE);
    setError(null);
    try {
      const url = await generateThumbnailImage(prompt);
      setConfig(prev => ({ ...prev, imageUrl: url }));
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to generate image. Please try again.');
      setStatus(AppStatus.READY);
    }
  };

  const updateConfig = (updates: Partial<ThumbnailConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
  };

  const downloadThumbnail = () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = 1280;
    canvas.height = 720;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      // Draw background
      ctx.drawImage(img, 0, 0, 1280, 720);

      // Draw overlay
      ctx.fillStyle = `rgba(0, 0, 0, ${config.overlayOpacity / 100})`;
      ctx.fillRect(0, 0, 1280, 720);

      // Draw text
      ctx.font = `${config.fontSize * 2}px ${config.fontFamily}`;
      ctx.fillStyle = config.fontColor;
      ctx.strokeStyle = config.strokeColor;
      ctx.lineWidth = config.strokeWidth * 4;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';

      const x = canvas.width / 2;
      const y = (config.textPosition.y / 100) * canvas.height;
      const lines = config.title.split('\n');
      const lineHeight = config.fontSize * 2.2;

      lines.forEach((line, i) => {
        const lineY = y + (i - (lines.length - 1) / 2) * lineHeight;
        ctx.strokeText(line.toUpperCase(), x, lineY);
        ctx.fillText(line.toUpperCase(), x, lineY);
      });

      const link = document.createElement('a');
      link.download = 'thumbnail.png';
      link.href = canvas.toDataURL('image/png');
      link.click();
    };
    img.src = config.imageUrl || 'https://picsum.photos/1280/720?grayscale';
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center max-w-7xl mx-auto">
      <header className="w-full text-center mb-10">
        <h1 className="text-4xl md:text-5xl font-black bg-gradient-to-r from-blue-400 to-purple-500 bg-clip-text text-transparent mb-2">
          ThumbnailAI Studio
        </h1>
        <p className="text-slate-400">Transform your script into high-converting video thumbnails in seconds.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 w-full">
        {/* Left Section: Inputs & Suggestions */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="bg-slate-800 p-6 rounded-2xl border border-slate-700 shadow-xl">
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
              <span className="text-blue-500">1.</span> Video Content
            </h2>
            <textarea
              placeholder="Paste your video script or describe your video topic..."
              className="w-full h-32 bg-slate-900 border border-slate-700 rounded-xl p-4 text-sm focus:ring-2 focus:ring-blue-500 outline-none mb-4"
              value={script}
              onChange={(e) => setScript(e.target.value)}
            />
            <button
              onClick={handleAnalyze}
              disabled={status === AppStatus.ANALYZING || !script}
              className="w-full py-3 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 font-bold rounded-xl transition-all shadow-lg"
            >
              {status === AppStatus.ANALYZING ? 'Analyzing Script...' : 'Get Suggestions'}
            </button>
          </div>

          {suggestions && (
            <div className="bg-slate-800 p-6 rounded-2xl border border-slate-700 shadow-xl animate-fade-in">
              <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                <span className="text-purple-500">2.</span> AI Suggestions
              </h2>

              <div className="mb-6">
                <p className="text-xs font-bold text-slate-500 uppercase mb-3">Trending Titles</p>
                <div className="space-y-2">
                  {suggestions.titles.map((title, i) => (
                    <button
                      key={i}
                      onClick={() => updateConfig({ title })}
                      className="w-full text-left p-2 rounded-lg bg-slate-900 border border-slate-700 hover:border-blue-500 text-xs transition-colors"
                    >
                      {title}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <p className="text-xs font-bold text-slate-500 uppercase mb-3">Background Prompts</p>
                <div className="space-y-2">
                  {suggestions.imagePrompts.map((prompt, i) => (
                    <button
                      key={i}
                      onClick={() => handleGenerateImage(prompt)}
                      disabled={status === AppStatus.GENERATING_IMAGE}
                      className="w-full text-left p-3 rounded-lg bg-slate-900 border border-slate-700 hover:border-purple-500 text-[10px] leading-tight transition-colors disabled:opacity-50"
                    >
                      {status === AppStatus.GENERATING_IMAGE ? 'Generating...' : `Generate: ${prompt.substring(0, 60)}...`}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Right Section: Preview & Editor */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="bg-slate-800 p-6 rounded-2xl border border-slate-700 shadow-xl overflow-hidden">
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
              <span className="text-green-500">3.</span> Live Designer
            </h2>

            <div className="relative group rounded-lg overflow-hidden border border-slate-600 shadow-2xl">
              <div 
                className="canvas-container w-full bg-slate-900 flex items-center justify-center"
                style={{ backgroundImage: config.imageUrl ? `url(${config.imageUrl})` : 'none' }}
              >
                {!config.imageUrl && (
                  <div className="text-slate-600 text-sm italic">Generate a background image to start</div>
                )}

                {/* Overlay */}
                <div 
                  className="absolute inset-0 bg-black pointer-events-none transition-opacity" 
                  style={{ opacity: config.overlayOpacity / 100 }} 
                />

                {/* Title Overlay */}
                <div 
                  className="absolute inset-x-4 flex flex-col items-center text-center leading-none uppercase pointer-events-none select-none"
                  style={{ 
                    top: `${config.textPosition.y}%`, 
                    transform: 'translateY(-50%)',
                    fontFamily: config.fontFamily,
                    fontSize: `${config.fontSize}px`,
                    color: config.fontColor,
                    textShadow: `0 0 10px rgba(0,0,0,0.5)`,
                    WebkitTextStroke: `${config.strokeWidth}px ${config.strokeColor}`
                  }}
                >
                  {config.title.split('\n').map((line, i) => (
                    <span key={i} className="block w-full filter drop-shadow-2xl">{line}</span>
                  ))}
                </div>
              </div>

              {status === AppStatus.GENERATING_IMAGE && (
                <div className="absolute inset-0 bg-slate-900/80 flex flex-col items-center justify-center text-center p-8 backdrop-blur-sm z-50">
                   <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                   <h3 className="text-xl font-bold text-white mb-2">Creating Background...</h3>
                   <p className="text-slate-400 text-sm max-w-md">Our AI is painting a custom cinematic background for your video. This usually takes 5-10 seconds.</p>
                </div>
              )}
            </div>

            <div className="mt-8 grid grid-cols-1 md:grid-cols-2 gap-8">
              <EditorControls config={config} onChange={updateConfig} />

              <div className="flex flex-col gap-4">
                <div className="p-4 bg-slate-900/50 rounded-xl border border-slate-700">
                  <h4 className="text-sm font-bold text-slate-500 uppercase mb-4">Design Tips</h4>
                  <ul className="text-xs space-y-3 text-slate-300">
                    <li className="flex gap-2">
                      <span className="text-blue-500">•</span> Use contrasting colors for text (Yellow/White on Dark)
                    </li>
                    <li className="flex gap-2">
                      <span className="text-blue-500">•</span> Keep text short - aim for 4-5 words max
                    </li>
                    <li className="flex gap-2">
                      <span className="text-blue-500">•</span> Stroke helps text stand out from busy backgrounds
                    </li>
                    <li className="flex gap-2">
                      <span className="text-blue-500">•</span> Use large bold fonts for mobile viewers
                    </li>
                  </ul>
                </div>

                <button
                  onClick={downloadThumbnail}
                  className="mt-auto w-full py-4 bg-gradient-to-r from-green-600 to-emerald-600 hover:from-green-500 hover:to-emerald-500 text-white font-black rounded-xl shadow-lg transition-transform active:scale-95"
                >
                  EXPORT 1280x720 PNG
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {error && (
        <div className="fixed bottom-4 right-4 bg-red-500 text-white px-6 py-3 rounded-lg shadow-2xl animate-bounce">
          {error}
        </div>
      )}

      <footer className="mt-20 text-slate-500 text-sm pb-8">
        © 2024 ThumbnailAI Studio • Powered by Gemini 3 & 2.5 Flash
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface SuggestionResponse {
  titles: string[];
  imagePrompts: string[];
}

