  type: 'icon' | 'shape';
  path: string;
  x: number;
  y: number;
  size: number;
  color: string;
  rotation: number;
}

export interface ThumbnailConfig {
  title: string;
  imageUrl: string | null;
  fontFamily: string;
  fontSize: number;
  fontColor: string;
  strokeColor: string;
  strokeWidth: number;
  textPosition: { x: number; y: number };
  overlayOpacity: number;
  graphics: GraphicElement[];
}

export enum AppStatus {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  GENERATING_IMAGE = 'GENERATING_IMAGE',
  READY = 'READY'
}

import React from 'react';
import { ThumbnailConfig, GraphicElement } from '../types';
import { FONT_FAMILIES, COLOR_PALETTES, ICON_PRESETS } from '../constants';

interface EditorControlsProps {
  config: ThumbnailConfig;
  onChange: (updates: Partial<ThumbnailConfig>) => void;
}

export const EditorControls: React.FC<EditorControlsProps> = ({ config, onChange }) => {
  const addGraphic = (type: string, path: string) => {
    const newGraphic: GraphicElement = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'icon',
      path,
      x: 50,
      y: 50,
      size: 80,
      color: '#ffff00',
      rotation: 0
    };
    onChange({ graphics: [...config.graphics, newGraphic] });
  };

  const removeGraphic = (id: string) => {
    onChange({ graphics: config.graphics.filter(g => g.id !== id) });
  };

  const updateGraphic = (id: string, updates: Partial<GraphicElement>) => {
    onChange({
      graphics: config.graphics.map(g => g.id === id ? { ...g, ...updates } : g)
    });
  };

  return (
    <div className="flex flex-col gap-6 p-4 bg-slate-800 rounded-xl border border-slate-700 max-h-[70vh] overflow-y-auto custom-scrollbar">
      <section>
        <label className="block text-xs font-bold uppercase tracking-wider mb-2 text-slate-500">1. Text Content</label>
        <textarea
          value={config.title}
          onChange={(e) => onChange({ title: e.target.value })}
          className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none h-20 uppercase font-bold text-sm"
        />
      </section>

      <section>
        <label className="block text-xs font-bold uppercase tracking-wider mb-2 text-slate-500">2. Font Style</label>
        <select
          value={config.fontFamily}
          onChange={(e) => onChange({ fontFamily: e.target.value })}
          className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2.5 text-white text-sm"
        >
          {FONT_FAMILIES.map((f) => (
            <option key={f.name} value={f.value} style={{ fontFamily: f.value }}>
              {f.name}
            </option>
          ))}
        </select>
      </section>

      <section>
        <label className="block text-xs font-bold uppercase tracking-wider mb-3 text-slate-500">3. Color Preset</label>
        <div className="grid grid-cols-4 gap-2">
          {COLOR_PALETTES.map((p) => (
            <button
              key={p.name}
              title={p.name}
              onClick={() => onChange({ fontColor: p.font, strokeColor: p.stroke })}
              className={`h-10 rounded-lg border-2 transition-transform hover:scale-105 ${config.fontColor === p.font && config.strokeColor === p.stroke ? 'border-white' : 'border-slate-700'}`}
              style={{ background: `linear-gradient(135deg, ${p.font} 50%, ${p.stroke} 50%)` }}
            />
          ))}
        </div>
      </section>

      <section className="space-y-4">
        <label className="block text-xs font-bold uppercase tracking-wider text-slate-500">4. Positioning & Size</label>
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="text-[10px] text-slate-400 block mb-1">Vertical ({config.textPosition.y}%)</label>
            <input
              type="range" min="0" max="100" value={config.textPosition.y}
              onChange={(e) => onChange({ textPosition: { ...config.textPosition, y: parseInt(e.target.value) } })}
              className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
            />
          </div>
          <div>
            <label className="text-[10px] text-slate-400 block mb-1">Horizontal ({config.textPosition.x}%)</label>
            <input
              type="range" min="0" max="100" value={config.textPosition.x}
              onChange={(e) => onChange({ textPosition: { ...config.textPosition, x: parseInt(e.target.value) } })}
              className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
            />
          </div>
        </div>
        <div>
          <label className="text-[10px] text-slate-400 block mb-1">Font Size ({config.fontSize}px)</label>
          <input
            type="range" min="20" max="180" value={config.fontSize}
            onChange={(e) => onChange({ fontSize: parseInt(e.target.value) })}
            className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
          />
        </div>
      </section>

      <section>
        <label className="block text-xs font-bold uppercase tracking-wider mb-3 text-slate-500">5. Graphic Elements</label>
        <div className="flex gap-2 mb-4 overflow-x-auto pb-2">
          {ICON_PRESETS.map((icon) => (
            <button
              key={icon.name}
              onClick={() => addGraphic('icon', icon.path)}
              className="p-2 bg-slate-700 hover:bg-slate-600 rounded-lg shrink-0"
            >
              <svg viewBox="0 0 24 24" className="w-6 h-6 fill-none stroke-white stroke-2">
                <path d={icon.path} />
              </svg>
            </button>
          ))}
        </div>

        {config.graphics.length > 0 && (
          <div className="space-y-4 pt-4 border-t border-slate-700">
            {config.graphics.map((g) => (
              <div key={g.id} className="p-3 bg-slate-900 rounded-lg relative group">
                <button 
                  onClick={() => removeGraphic(g.id)}
                  className="absolute -top-2 -right-2 w-5 h-5 bg-red-500 text-white text-[10px] rounded-full flex items-center justify-center shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  ✕
                </button>
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="text-[9px] text-slate-500 block">Position X/Y</label>
                    <div className="flex gap-1">
