            >
              {status === AppStatus.ANALYZING ? 'ANALYZING...' : 'GET CONCEPTS'}
            </button>
          </div>

          {suggestions && (
            <div className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-xl overflow-hidden">
              <h2 className="text-lg font-bold mb-4 text-purple-400">2. CONCEPTS</h2>
