                  <div className="space-y-1">
                    {suggestions.titles.map((title, i) => (
                      <button key={i} onClick={() => updateConfig({ title })} className="w-full text-left p-2 rounded bg-slate-900 hover:bg-slate-700 text-[11px] truncate">{title}</button>
                    ))}
                  </div>
                </div>
                <div>
                  <p className="text-[10px] font-bold text-slate-500 uppercase mb-2">Art Prompts</p>
                  <div className="space-y-1">
