                      <button key={i} onClick={() => handleGenerateImage(p)} disabled={status === AppStatus.GENERATING_IMAGE} className="w-full text-left p-2 rounded bg-slate-900 hover:bg-slate-700 text-[10px] leading-tight transition-opacity disabled:opacity-50">{p.substring(0, 40)}...</button>
