      <section className="bg-slate-900/50 p-3 rounded-lg border border-slate-700">
        <div className="flex justify-between items-center mb-3">
          <label className="text-xs font-black text-blue-400 uppercase tracking-widest">Line 1 Text</label>
        </div>
        <input
          type="text"
          value={config.line1Text}
          onChange={(e) => onChange({ line1Text: e.target.value })}
          className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-white font-bold uppercase text-sm mb-4 outline-none focus:border-blue-500"
        />
        <ColorSelector 
          label="Color" 
          selected={config.line1Color} 
          onSelect={(line1Color) => onChange({ line1Color })} 
        />
        <div className="grid grid-cols-2 gap-3 mt-3">
          <div>
            <label className="text-[10px] text-slate-400 flex justify-between mb-1 uppercase font-bold">
              <span>Size</span>
              <span className="text-blue-400">{config.line1FontSize}px</span>
            </label>
            <input
              type="range" min="20" max="180" value={config.line1FontSize}
              onChange={(e) => onChange({ line1FontSize: parseInt(e.target.value) })}
              className="w-full h-1 bg-slate-700 rounded appearance-none accent-blue-500"
            />
          </div>
          <div>
            <label className="text-[10px] text-slate-400 flex justify-between mb-1 uppercase font-bold">
              <span>Stroke</span>
              <span className="text-blue-400">{config.line1StrokeWidth.toFixed(1)}</span>
            </label>
            <input
              type="range" min="0" max="10" step="0.5" value={config.line1StrokeWidth}
              onChange={(e) => onChange({ line1StrokeWidth: parseFloat(e.target.value) })}
              className="w-full h-1 bg-slate-700 rounded appearance-none accent-blue-500"
            />
          </div>
        </div>
      </section>

      <section className="bg-slate-900/50 p-3 rounded-lg border border-slate-700">
