import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppStatus, SuggestionResponse, ThumbnailConfig, GraphicElement } from './types';
import { DEFAULT_CONFIG } from './constants';
import { analyzeScript, generateThumbnailImage } from './services/geminiService';
import { EditorControls } from './components/EditorControls';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [script, setScript] = useState('');
  const [language, setLanguage] = useState('Vietnamese');
  const [suggestions, setSuggestions] = useState<SuggestionResponse | null>(null);
  const [config, setConfig] = useState<ThumbnailConfig>(DEFAULT_CONFIG);
  const [error, setError] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [copyStatus, setCopyStatus] = useState<number | null>(null);

  const containerRef = useRef<HTMLDivElement>(null);

  const handleAnalyze = async () => {
    if (!script.trim()) return;
    setStatus(AppStatus.ANALYZING);
    setError(null);
    try {
      const result = await analyzeScript(script, language);
      setSuggestions(result);
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to analyze script. Please try again.');
      setStatus(AppStatus.IDLE);
    }
  };

  const handleGenerateImage = async (prompt: string) => {
    setStatus(AppStatus.GENERATING_IMAGE);
    setError(null);
    try {
      const url = await generateThumbnailImage(prompt);
      setConfig(prev => ({ ...prev, imageUrl: url }));
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to generate image. Please try again.');
      setStatus(AppStatus.READY);
    }
  };

  const applyTitleSuggestion = (title: string) => {
    const words = title.split(' ');
    if (words.length > 3) {
      const middle = Math.ceil(words.length / 2);
      setConfig(prev => ({
        ...prev,
        line1Text: words.slice(0, middle).join(' ').toUpperCase(),
        line2Text: words.slice(middle).join(' ').toUpperCase(),
        showLine2: true
      }));
    } else {
      setConfig(prev => ({
        ...prev,
        line1Text: title.toUpperCase(),
        showLine2: false
      }));
    }
  };

  const handleCopyPrompt = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopyStatus(index);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const updatePrompt = (index: number, newText: string) => {
    if (!suggestions) return;
    const newPrompts = [...suggestions.imagePrompts];
    newPrompts[index] = newText;
    setSuggestions({ ...suggestions, imagePrompts: newPrompts });
  };

  const updateConfig = (updates: Partial<ThumbnailConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const constrainedX = Math.max(0, Math.min(100, x));
    const constrainedY = Math.max(0, Math.min(100, y));

    updateConfig({
      textPosition: { x: constrainedX, y: constrainedY }
    });
  }, [isDragging]);

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
  }, []);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    } else {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, handleMouseMove, handleMouseUp]);

  const drawToCanvas = (ctx: CanvasRenderingContext2D, width: number, height: number, background: HTMLImageElement) => {
    ctx.clearRect(0, 0, width, height);
    ctx.drawImage(background, 0, 0, width, height);

    ctx.fillStyle = `rgba(0, 0, 0, ${config.overlayOpacity / 100})`;
    ctx.fillRect(0, 0, width, height);

    config.graphics.forEach(g => {
      ctx.save();
      const gx = (g.x / 100) * width;
      const gy = (g.y / 100) * height;
      ctx.translate(gx, gy);
      ctx.rotate((g.rotation * Math.PI) / 180);
      const p = new Path2D(g.path);
      const scale = g.size / 24; 
      ctx.scale(scale, scale);
      ctx.translate(-12, -12); 
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 2;
      ctx.stroke(p);
      ctx.fillStyle = g.color;
      ctx.fill(p);
      ctx.restore();
    });

    const tx = (config.textPosition.x / 100) * width;
    const ty = (config.textPosition.y / 100) * height;

    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.lineJoin = 'round';

    const drawLine = (text: string, color: string, stroke: string, fontSize: number, strokeWidth: number, y: number) => {
        const scaledFontSize = fontSize * (width / 640);
        ctx.font = `${scaledFontSize}px ${config.fontFamily}`; 
        ctx.lineWidth = strokeWidth * (width / 320);
        ctx.strokeStyle = stroke;
        ctx.fillStyle = color;
        ctx.shadowColor = 'rgba(0,0,0,0.7)';
        ctx.shadowBlur = 20;
        ctx.strokeText(text.toUpperCase(), tx, y);
        ctx.fillText(text.toUpperCase(), tx, y);
    };

    if (config.showLine2) {
      const line1Offset = (config.line1FontSize * (width/640)) * 0.5;
      const line2Offset = (config.line2FontSize * (width/640)) * 0.5;
      drawLine(config.line1Text, config.line1Color, config.line1StrokeColor, config.line1FontSize, config.line1StrokeWidth, ty - line1Offset);
      drawLine(config.line2Text, config.line2Color, config.line2StrokeColor, config.line2FontSize, config.line2StrokeWidth, ty + line2Offset);
    } else {
      drawLine(config.line1Text, config.line1Color, config.line1StrokeColor, config.line1FontSize, config.line1StrokeWidth, ty);
    }
  };

  const downloadThumbnail = () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = 1280;
    canvas.height = 720;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      drawToCanvas(ctx, 1280, 720, img);
      const link = document.createElement('a');
      link.download = 'thumbnail.png';
      link.href = canvas.toDataURL('image/png');
      link.click();
    };
    img.src = config.imageUrl || 'https://picsum.photos/1280/720?grayscale';
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center max-w-7xl mx-auto">
      <header className="w-full text-center mb-10">
        <h1 className="text-4xl md:text-5xl font-black bg-gradient-to-r from-blue-400 to-purple-500 bg-clip-text text-transparent mb-2 italic text-stroke">
          THUMBNAIL AI PRO
        </h1>
        <p className="text-slate-400 text-sm tracking-widest uppercase">The Ultimate Video Hook Generator</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 w-full">
        {/* COLUMN 1: LEFT SIDEBAR (IDEATION + EDITOR CONTROLS) */}
        <div className="lg:col-span-3 flex flex-col gap-6 h-fit">
          <div className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-xl">
            <h2 className="text-lg font-bold mb-4 text-blue-400 uppercase text-xs tracking-tighter">1. Ideation</h2>

            <label className="text-[10px] text-slate-500 font-bold uppercase mb-2 block">Output Language</label>
            <div className="flex gap-1 mb-4">
              {[
                { label: 'Tiếng Việt', value: 'Vietnamese' },
                { label: 'English', value: 'English' },
                { label: '中文', value: 'Chinese' }
              ].map((lang) => (
                <button
                  key={lang.value}
                  onClick={() => setLanguage(lang.value)}
                  className={`flex-1 py-1.5 rounded-lg text-[9px] font-bold border transition-all ${
                    language === lang.value 
                    ? 'bg-blue-600 border-blue-400 text-white shadow-lg' 
                    : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {lang.label}
                </button>
              ))}
            </div>

            <textarea
              placeholder="Script or video details..."
              className="w-full h-24 bg-slate-900 border border-slate-700 rounded-xl p-3 text-sm focus:ring-2 focus:ring-blue-500 outline-none mb-4"
              value={script}
              onChange={(e) => setScript(e.target.value)}
            />
            <button
              onClick={handleAnalyze}
              disabled={status === AppStatus.ANALYZING || !script}
              className="w-full py-3 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 font-black rounded-xl transition-all shadow-lg text-sm"
            >
              {status === AppStatus.ANALYZING ? 'ANALYZING...' : 'GENERATE IDEAS'}
            </button>
          </div>

          <div className="bg-slate-800 p-1 rounded-2xl border border-slate-700 shadow-xl">
             <div className="p-4 border-b border-slate-700">
               <h2 className="text-lg font-bold text-blue-400 uppercase text-xs tracking-tighter">2. Customization</h2>
             </div>
             <EditorControls config={config} onChange={updateConfig} />
          </div>
        </div>

        {/* COLUMN 2: CENTER (PREVIEW AREA) */}
        <div className="lg:col-span-6 flex flex-col gap-6">
          <div className="bg-slate-800 p-4 rounded-2xl border border-slate-700 shadow-2xl relative">
            <div 
              ref={containerRef}
              onMouseDown={handleMouseDown}
              className={`canvas-container w-full rounded-xl cursor-move select-none ${isDragging ? 'ring-2 ring-blue-500 ring-offset-4 ring-offset-slate-800' : ''}`}
              style={{ backgroundImage: config.imageUrl ? `url(${config.imageUrl})` : 'linear-gradient(45deg, #1e293b, #0f172a)' }}
            >
              {!config.imageUrl && (
                <div className="absolute inset-0 flex items-center justify-center text-slate-600 text-sm font-bold opacity-50 uppercase tracking-widest pointer-events-none">Preview Area</div>
              )}

              <div className="absolute inset-0 bg-black pointer-events-none" style={{ opacity: config.overlayOpacity / 100 }} />

              {config.graphics.map(g => (
                <div key={g.id} className="absolute pointer-events-none" style={{ left: `${g.x}%`, top: `${g.y}%`, transform: `translate(-50%, -50%) rotate(${g.rotation}deg)` }}>
                  <svg viewBox="0 0 24 24" style={{ width: `${g.size / 6}px`, height: `${g.size / 6}px`, filter: 'drop-shadow(0 4px 10px rgba(0,0,0,0.8))' }} className="fill-none stroke-black stroke-1">
                    <path d={g.path} fill={g.color} />
                  </svg>
                </div>
              ))}

              <div 
                className={`absolute flex flex-col items-center text-center leading-[1.1] uppercase pointer-events-none transition-all ${isDragging ? 'duration-75 scale-105' : 'duration-300'}`}
                style={{ 
                  left: `${config.textPosition.x}%`,
                  top: `${config.textPosition.y}%`, 
                  transform: 'translate(-50%, -50%)',
                  fontFamily: config.fontFamily,
                }}
              >
                <span 
                  className="block whitespace-nowrap filter drop-shadow-2xl" 
                  style={{ 
                    color: config.line1Color,
                    fontSize: `${config.line1FontSize / 1.5}px`,
                    WebkitTextStroke: `${config.line1StrokeWidth / 1.5}px black`,
                    textShadow: '0 10px 40px rgba(0,0,0,0.9)'
                  }}
                >
                  {config.line1Text}
                </span>
                {config.showLine2 && (
                  <span 
                    className="block whitespace-nowrap filter drop-shadow-2xl" 
                    style={{ 
                      color: config.line2Color,
                      fontSize: `${config.line2FontSize / 1.5}px`,
                      WebkitTextStroke: `${config.line2StrokeWidth / 1.5}px black`,
                      textShadow: '0 10px 40px rgba(0,0,0,0.9)'
                    }}
                  >
                    {config.line2Text}
                  </span>
                )}
                <div className={`mt-2 border border-white/30 px-2 py-0.5 rounded text-[8px] tracking-tighter bg-black/40 text-white/70 transition-opacity ${isDragging ? 'opacity-100' : 'opacity-0'}`}>
                  MOVING TEXT...
                </div>
              </div>

              {status === AppStatus.GENERATING_IMAGE && (
                <div className="absolute inset-0 bg-slate-900/95 flex flex-col items-center justify-center text-center p-8 backdrop-blur-sm z-50 rounded-xl pointer-events-none">
                  <div className="w-10 h-10 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                  <p className="text-white font-black animate-pulse tracking-widest text-xs">PAINTING BACKGROUND...</p>
                </div>
              )}
            </div>

            <div className="mt-4 flex justify-between items-center">
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
                💡 PRO TIP: Drag text to the focal point
              </p>
              <button onClick={downloadThumbnail} className="px-8 py-2.5 bg-green-600 hover:bg-green-500 text-white font-black rounded-lg shadow-lg text-sm tracking-wider active:scale-95 transition-transform uppercase">Export Image</button>
            </div>
          </div>

          <div className="bg-slate-900/40 p-4 rounded-xl border border-slate-800">
             <div className="grid grid-cols-4 gap-4 text-center">
                <div className="flex flex-col items-center gap-1"><span className="text-[9px] text-slate-500 font-black uppercase">Plan</span></div>
                <div className="flex flex-col items-center gap-1"><span className="text-[9px] text-slate-500 font-black uppercase">Create</span></div>
                <div className="flex flex-col items-center gap-1"><span className="text-[9px] text-blue-400 font-black underline uppercase">Review</span></div>
                <div className="flex flex-col items-center gap-1"><span className="text-[9px] text-slate-500 font-black uppercase">Viral</span></div>
             </div>
          </div>
        </div>

        {/* COLUMN 3: RIGHT SIDEBAR (AI SUGGESTIONS) */}
        <div className="lg:col-span-3 flex flex-col gap-6">
          {suggestions ? (
            <div className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-xl overflow-hidden flex flex-col h-fit max-h-[85vh]">
              <h2 className="text-lg font-bold mb-4 text-purple-400 uppercase text-xs tracking-tighter">3. AI Suggestions</h2>
