                    >
                      {lang.label}
                    </button>
                  ))}
                </div>

                <div className="flex flex-col gap-2">
                  <button
                    onClick={handleAnalyze}
                    disabled={status === AppStatus.ANALYZING || !script}
                    className="w-full py-3 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 font-black rounded-xl transition-all shadow-lg text-xs"
                  >
                    {status === AppStatus.ANALYZING ? 'ANALYZING...' : 'GENERATE IDEAS'}
