            <div className="mt-4 flex justify-between items-center">
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
                💡 PRO TIP: Drag text on the image to position it
              </p>
              <button onClick={downloadThumbnail} className="px-8 py-2.5 bg-green-600 hover:bg-green-500 text-white font-black rounded-lg shadow-lg text-sm tracking-wider active:scale-95 transition-transform uppercase">Export Final Image</button>
            </div>
          </div>

          <div className="bg-slate-900/40 p-4 rounded-xl border border-slate-800">
             <div className="grid grid-cols-4 gap-4 text-center">
                <div className="flex flex-col items-center gap-1"><span className="text-[9px] text-slate-500 font-black uppercase">Ideate</span></div>
                <div className="flex flex-col items-center gap-1"><span className="text-[9px] text-slate-500 font-black uppercase">Refine</span></div>
                <div className="flex flex-col items-center gap-1"><span className="text-[9px] text-blue-400 font-black underline uppercase">Export</span></div>
                <div className="flex flex-col items-center gap-1"><span className="text-[9px] text-slate-500 font-black uppercase">Viral</span></div>
             </div>
          </div>
        </div>

        {/* RIGHT COLUMN (3 UNITS): AI SUGGESTIONS */}
        <div className="lg:col-span-3 flex flex-col gap-6">
          {suggestions ? (
            <div className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-xl overflow-hidden flex flex-col h-fit max-h-[85vh]">
              <h2 className="text-lg font-bold mb-4 text-purple-400 uppercase text-xs tracking-tighter">Step 3: AI Ideas</h2>
              <div className="space-y-6 overflow-y-auto pr-1 custom-scrollbar text-xs">
                <div>
                  <p className="text-[10px] font-bold text-slate-500 uppercase mb-2 sticky top-0 bg-slate-800 py-1 z-10">Recommended Titles</p>
                  <div className="space-y-1">
                    {suggestions.titles.map((title, i) => (
                      <button key={i} onClick={() => applyTitleSuggestion(title)} className="w-full text-left p-2 rounded bg-slate-900 hover:bg-slate-700 truncate transition-colors uppercase font-bold text-[10px]">{title}</button>
                    ))}
                  </div>
                </div>
                <div>
                  <p className="text-[10px] font-bold text-slate-500 uppercase mb-2 sticky top-0 bg-slate-800 py-1 z-10">Image Prompts</p>
                  <div className="space-y-3">
                    {suggestions.imagePrompts.map((p, i) => (
                      <div key={i} className="flex flex-col gap-2 p-2 rounded bg-slate-900 border border-slate-700">
                        <textarea
                          value={p}
                          onChange={(e) => updatePrompt(i, e.target.value)}
                          className="w-full bg-slate-950 border border-slate-800 rounded p-2 text-[10px] text-slate-300 min-h-[60px] outline-none focus:border-purple-500 transition-colors resize-none"
                        />
                        <div className="flex gap-1">
                          <button
                            onClick={() => handleCopyPrompt(p, i)}
                            className="flex-1 py-1 px-1 rounded bg-slate-800 hover:bg-slate-700 text-[8px] font-bold transition-colors text-slate-400 flex items-center justify-center gap-1"
                          >
                            {copyStatus === i ? 'COPIED' : 'COPY'}
                          </button>
                          <button
                            onClick={() => handleGenerateImage(p)}
                            disabled={status === AppStatus.GENERATING_IMAGE}
                            className="flex-[2] py-1 px-1 rounded bg-purple-600 hover:bg-purple-500 text-[8px] font-black text-white transition-all disabled:opacity-50"
                          >
                            {status === AppStatus.GENERATING_IMAGE ? 'PAINTING...' : 'PAINT'}
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="bg-slate-800/40 p-8 rounded-2xl border border-dashed border-slate-700 flex flex-col items-center justify-center text-center opacity-50">
              <svg className="w-12 h-12 text-slate-600 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
              </svg>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest leading-loose">Enter your script above<br/>to see AI suggestions here</p>
            </div>
          )}
        </div>
      </div>

      {error && (
        <div className="fixed bottom-6 right-6 bg-red-600 text-white px-6 py-4 rounded-2xl shadow-2xl z-[100] border-2 border-white/20 font-bold">
          {error}
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppStatus, SuggestionResponse, ThumbnailConfig, GraphicElement } from './types';
import { DEFAULT_CONFIG } from './constants';
import { analyzeScript, generateThumbnailImage } from './services/geminiService';
import { EditorControls } from './components/EditorControls';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [script, setScript] = useState('');
  const [language, setLanguage] = useState('Vietnamese');
  const [suggestions, setSuggestions] = useState<SuggestionResponse | null>(null);
  const [config, setConfig] = useState<ThumbnailConfig>(DEFAULT_CONFIG);
  const [error, setError] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [copyStatus, setCopyStatus] = useState<number | null>(null);

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAnalyze = async () => {
    if (!script.trim()) return;
    setStatus(AppStatus.ANALYZING);
    setError(null);
    try {
      const result = await analyzeScript(script, language);
      setSuggestions(result);
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to analyze script. Please try again.');
      setStatus(AppStatus.IDLE);
    }
  };

  const handleGenerateImage = async (prompt: string) => {
    setStatus(AppStatus.GENERATING_IMAGE);
    setError(null);
    try {
      const url = await generateThumbnailImage(prompt);
      setConfig(prev => ({ ...prev, imageUrl: url }));
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to generate image. Please try again.');
      setStatus(AppStatus.READY);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, imageUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  const applyTitleSuggestion = (title: string) => {
    const words = title.split(' ');
    if (words.length > 3) {
      const middle = Math.ceil(words.length / 2);
      setConfig(prev => ({
        ...prev,
        line1Text: words.slice(0, middle).join(' ').toUpperCase(),
        line2Text: words.slice(middle).join(' ').toUpperCase(),
        showLine2: true
      }));
    } else {
      setConfig(prev => ({
        ...prev,
        line1Text: title.toUpperCase(),
        showLine2: false
      }));
    }
  };

  const handleCopyPrompt = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopyStatus(index);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const updatePrompt = (index: number, newText: string) => {
    if (!suggestions) return;
    const newPrompts = [...suggestions.imagePrompts];
    newPrompts[index] = newText;
    setSuggestions({ ...suggestions, imagePrompts: newPrompts });
  };

  const updateConfig = (updates: Partial<ThumbnailConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const constrainedX = Math.max(0, Math.min(100, x));
    const constrainedY = Math.max(0, Math.min(100, y));

    updateConfig({
      textPosition: { x: constrainedX, y: constrainedY }
    });
  }, [isDragging]);

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
  }, []);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    } else {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, handleMouseMove, handleMouseUp]);

  const downloadThumbnail = () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = 1280;
    canvas.height = 720;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
        // Simple re-implementation of draw logic for canvas export
        ctx.clearRect(0, 0, 1280, 720);
        ctx.drawImage(img, 0, 0, 1280, 720);
        ctx.fillStyle = `rgba(0, 0, 0, ${config.overlayOpacity / 100})`;
        ctx.fillRect(0, 0, 1280, 720);

        config.graphics.forEach(g => {
            ctx.save();
            ctx.translate((g.x / 100) * 1280, (g.y / 100) * 720);
            ctx.rotate((g.rotation * Math.PI) / 180);
            const p = new Path2D(g.path);
            const scale = (g.size / 24) * 4; 
            ctx.scale(scale, scale);
            ctx.translate(-12, -12); 
            ctx.fillStyle = g.color;
            ctx.fill(p);
            ctx.restore();
        });

        const tx = (config.textPosition.x / 100) * 1280;
        const ty = (config.textPosition.y / 100) * 720;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.lineJoin = 'round';

        const drawLine = (text: string, color: string, fontSize: number, strokeWidth: number, y: number) => {
            ctx.font = `bold ${fontSize * 2}px ${config.fontFamily}`; 
            ctx.lineWidth = strokeWidth * 4;
            ctx.strokeStyle = 'black';
            ctx.fillStyle = color;
            ctx.strokeText(text.toUpperCase(), tx, y);
            ctx.fillText(text.toUpperCase(), tx, y);
        };

        if (config.showLine2) {
            drawLine(config.line1Text, config.line1Color, config.line1FontSize, config.line1StrokeWidth, ty - (config.line1FontSize));
            drawLine(config.line2Text, config.line2Color, config.line2FontSize, config.line2StrokeWidth, ty + (config.line2FontSize));
        } else {
            drawLine(config.line1Text, config.line1Color, config.line1FontSize, config.line1StrokeWidth, ty);
        }

      const link = document.createElement('a');
      link.download = `thumbnail-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    };
    img.src = config.imageUrl || 'https://picsum.photos/1280/720?grayscale';
  };

  return (
    <div className="flex flex-col h-screen max-h-screen overflow-hidden bg-slate-950 text-slate-100">
      {/* HEADERBAR */}
      <header className="h-14 flex items-center justify-between px-6 border-b border-slate-800 bg-slate-900/80 backdrop-blur-md z-50">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
          </div>
          <span className="font-black tracking-tighter text-xl bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">THUMBNAIL.AI</span>
          <span className="hidden sm:inline-block px-2 py-0.5 rounded text-[10px] bg-slate-800 text-slate-400 font-bold border border-slate-700">STUDIO PRO</span>
        </div>

        <div className="flex items-center gap-4">
          <button onClick={() => setConfig(DEFAULT_CONFIG)} className="text-xs font-bold text-slate-400 hover:text-white transition-colors">RESET</button>
          <div className="h-4 w-px bg-slate-700 mx-2" />
          <button 
            onClick={downloadThumbnail} 
            className="flex items-center gap-2 px-4 py-1.5 bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-black rounded-full transition-all shadow-lg shadow-indigo-500/20 active:scale-95"
          >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
            EXPORT IMAGE
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* LEFT PANEL: STUDIO CONTROLS */}
        <aside className="w-[340px] border-r border-slate-800 bg-slate-900/40 flex flex-col overflow-hidden">
          <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-6">

            {/* Step 1: Concept */}
            <div className="space-y-4">
              <div className="flex items-center gap-2 mb-2">
                <span className="w-5 h-5 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-[10px] font-bold text-slate-400">1</span>
                <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Concept Ideation</h3>
              </div>

              <div className="flex flex-col gap-3">
                <div className="flex gap-1">
                  {['Vietnamese', 'English'].map((lang) => (
                    <button
                      key={lang}
                      onClick={() => setLanguage(lang)}
                      className={`flex-1 py-1.5 rounded-lg text-[10px] font-bold transition-all border ${language === lang ? 'bg-indigo-600/10 border-indigo-500 text-indigo-400' : 'bg-slate-800/50 border-slate-700 text-slate-500'}`}
                    >
                      {lang === 'Vietnamese' ? 'Tiếng Việt' : 'English'}
                    </button>
                  ))}
                </div>

                <textarea
                  placeholder="Paste script or describe your video topic..."
                  className="w-full h-28 bg-slate-950/50 border border-slate-800 rounded-xl p-3 text-sm focus:ring-1 focus:ring-indigo-500 outline-none transition-all resize-none"
                  value={script}
                  onChange={(e) => setScript(e.target.value)}
                />

                <div className="flex gap-2">
                  <button
                    onClick={handleAnalyze}
                    disabled={status === AppStatus.ANALYZING || !script}
