        {config.graphics.length > 0 && (
          <div className="mt-4 grid grid-cols-1 gap-2">
            {config.graphics.map((g) => (
              <div key={g.id} className="flex items-center justify-between p-2.5 bg-slate-900/50 rounded-lg border border-slate-800 group hover:border-slate-600 transition-all">
                <div className="flex items-center gap-3">
