                   <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">LAYER_{g.id.substr(0,4)}</span>
                </div>
                <button onClick={() => removeGraphic(g.id)} className="opacity-0 group-hover:opacity-100 transition-all text-red-500 hover:text-red-400 text-[10px] font-bold px-2 py-0.5 hover:bg-red-500/10 rounded">DELETE</button>
