};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppStatus, SuggestionResponse, ThumbnailConfig } from './types';
import { DEFAULT_CONFIG } from './constants';
import { analyzeScript, generateThumbnailImage } from './services/geminiService';
import { EditorControls } from './components/EditorControls';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [script, setScript] = useState('');
  const [language, setLanguage] = useState('Vietnamese');
  const [suggestions, setSuggestions] = useState<SuggestionResponse | null>(null);
  const [config, setConfig] = useState<ThumbnailConfig>(DEFAULT_CONFIG);
  const [error, setError] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [copyStatus, setCopyStatus] = useState<number | null>(null);
  const [previewScale, setPreviewScale] = useState(1);

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const updateScale = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth;
        setPreviewScale(width / 1280);
      }
    };
    updateScale();
    window.addEventListener('resize', updateScale);
    return () => window.removeEventListener('resize', updateScale);
  }, []);

  const handleAnalyze = async () => {
    if (!script.trim()) return;
    setStatus(AppStatus.ANALYZING);
    setError(null);
    try {
      const result = await analyzeScript(script, language);
      setSuggestions(result);
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to analyze script. Please try again.');
      setStatus(AppStatus.IDLE);
    }
  };

  const handleGenerateImage = async (prompt: string) => {
    setStatus(AppStatus.GENERATING_IMAGE);
    setError(null);
    try {
      const url = await generateThumbnailImage(prompt);
      setConfig(prev => ({ ...prev, imageUrl: url }));
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to generate image. Please try again.');
      setStatus(AppStatus.READY);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, imageUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  const applyTitleSuggestion = (title: string) => {
    const words = title.split(' ');
    if (words.length > 3) {
      const middle = Math.ceil(words.length / 2);
      setConfig(prev => ({
        ...prev,
        line1Text: words.slice(0, middle).join(' ').toUpperCase(),
        line2Text: words.slice(middle).join(' ').toUpperCase(),
        showLine2: true
      }));
    } else {
      setConfig(prev => ({
        ...prev,
        line1Text: title.toUpperCase(),
        showLine2: false
      }));
    }
  };

  const handleCopyPrompt = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopyStatus(index);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const updatePrompt = (index: number, newText: string) => {
    if (!suggestions) return;
    const newPrompts = [...suggestions.imagePrompts];
    newPrompts[index] = newText;
    setSuggestions({ ...suggestions, imagePrompts: newPrompts });
  };

  const updateConfig = (updates: Partial<ThumbnailConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!textRef.current || !containerRef.current) return;
    setIsDragging(true);
    const textRect = textRef.current.getBoundingClientRect();
    const offsetX = e.clientX - (textRect.left + textRect.width / 2);
    const offsetY = e.clientY - (textRect.top + textRect.height / 2);
    setDragOffset({ x: offsetX, y: offsetY });
    e.stopPropagation();
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const adjustedX = e.clientX - dragOffset.x;
    const adjustedY = e.clientY - dragOffset.y;
    const x = ((adjustedX - rect.left) / rect.width) * 100;
    const y = ((adjustedY - rect.top) / rect.height) * 100;
    updateConfig({ textPosition: { x: Math.max(0, Math.min(100, x)), y: Math.max(0, Math.min(100, y)) } });
  }, [isDragging, dragOffset]);

  const handleMouseUp = useCallback(() => setIsDragging(false), []);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'grabbing';
    } else {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = '';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, handleMouseMove, handleMouseUp]);

  const downloadThumbnail = () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1280;
    canvas.height = 720;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
        ctx.clearRect(0, 0, 1280, 720);
        ctx.drawImage(img, 0, 0, 1280, 720);
        ctx.fillStyle = `rgba(0, 0, 0, ${config.overlayOpacity / 100})`;
        ctx.fillRect(0, 0, 1280, 720);

        const tx = (config.textPosition.x / 100) * 1280;
        const ty = (config.textPosition.y / 100) * 720;
        ctx.textBaseline = 'middle';
        ctx.lineJoin = 'round';

        const drawLine = (text: string, color: string, color2: string, isGradient: boolean, fontSize: number, strokeWidth: number, strokeColor: string, align: 'left' | 'center' | 'right', italic: boolean, underline: boolean, shadowBlur: number, shadowOffset: number, shadowColor: string, y: number) => {
            const fontStyle = italic ? 'italic' : '';
            ctx.save();
            ctx.font = `${fontStyle} bold ${fontSize}px ${config.fontFamily}`; 
            ctx.textAlign = align;

            // Apply Shadow
            ctx.shadowColor = shadowColor;
            ctx.shadowBlur = shadowBlur;
            ctx.shadowOffsetX = shadowOffset;
            ctx.shadowOffsetY = shadowOffset;

            // Gradient handle
            if (isGradient) {
              const gradient = ctx.createLinearGradient(tx, y - fontSize/2, tx, y + fontSize/2);
              gradient.addColorStop(0, color);
              gradient.addColorStop(1, color2);
              ctx.fillStyle = gradient;
            } else {
              ctx.fillStyle = color;
            }

            // Stroke
            if (strokeWidth > 0) {
              ctx.lineWidth = strokeWidth * 2; 
              ctx.strokeStyle = strokeColor;
              ctx.strokeText(text.toUpperCase(), tx, y);
            }

            // Fill
            ctx.fillText(text.toUpperCase(), tx, y);

            if (underline) {
              const textWidth = ctx.measureText(text.toUpperCase()).width;
              let lineXStart = tx;
              if (align === 'center') lineXStart = tx - textWidth / 2;
              else if (align === 'right') lineXStart = tx - textWidth;
              const lineY = y + fontSize * 0.45;
              ctx.beginPath();
              ctx.moveTo(lineXStart, lineY);
              ctx.lineTo(lineXStart + textWidth, lineY);
              ctx.lineWidth = fontSize * 0.08;
              ctx.strokeStyle = isGradient ? color : color; // simplify for now
              ctx.stroke();
            }
            ctx.restore();
        };

        if (config.showLine2) {
            drawLine(config.line1Text, config.line1Color, config.line1Color2, config.line1IsGradient, config.line1FontSize, config.line1StrokeWidth, config.line1StrokeColor, config.line1Align, config.line1Italic, config.line1Underline, config.line1ShadowBlur, config.line1ShadowOffset, config.line1ShadowColor, ty - (config.line1FontSize / 2));
            drawLine(config.line2Text, config.line2Color, config.line2Color2, config.line2IsGradient, config.line2FontSize, config.line2StrokeWidth, config.line2StrokeColor, config.line2Align, config.line2Italic, config.line2Underline, config.line2ShadowBlur, config.line2ShadowOffset, config.line2ShadowColor, ty + (config.line2FontSize / 2));
        } else {
            drawLine(config.line1Text, config.line1Color, config.line1Color2, config.line1IsGradient, config.line1FontSize, config.line1StrokeWidth, config.line1StrokeColor, config.line1Align, config.line1Italic, config.line1Underline, config.line1ShadowBlur, config.line1ShadowOffset, config.line1ShadowColor, ty);
        }

      const link = document.createElement('a');
      link.download = `thumbnail-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    };
    img.src = config.imageUrl || 'https://picsum.photos/1280/720?grayscale';
  };

  const getTextStyle = (line: 'line1' | 'line2') => {
    const isLine1 = line === 'line1';
    const c = config;
    const txtColor = isLine1 ? c.line1Color : c.line2Color;
    const txtColor2 = isLine1 ? c.line1Color2 : c.line2Color2;
    const isGrad = isLine1 ? c.line1IsGradient : c.line2IsGradient;
    const sColor = isLine1 ? c.line1ShadowColor : c.line2ShadowColor;
    const sBlur = isLine1 ? c.line1ShadowBlur : c.line2ShadowBlur;
    const sOffset = isLine1 ? c.line1ShadowOffset : c.line2ShadowOffset;
    const strokeW = isLine1 ? c.line1StrokeWidth : c.line2StrokeWidth;
    const strokeC = isLine1 ? c.line1StrokeColor : c.line2StrokeColor;
    const align = isLine1 ? c.line1Align : c.line2Align;
    const fSize = isLine1 ? c.line1FontSize : c.line2FontSize;
    const italic = isLine1 ? c.line1Italic : c.line2Italic;
    const underline = isLine1 ? c.line1Underline : c.line2Underline;

    return {
      fontSize: `${fSize * previewScale}px`,
      WebkitTextStroke: `${strokeW * previewScale}px ${strokeC}`,
      textAlign: align as any,
      fontStyle: italic ? 'italic' : 'normal',
      textDecoration: underline ? 'underline' : 'none',
      width: '100%',
      // Gradient Text Logic
      ...(isGrad ? {
        backgroundImage: `linear-gradient(to bottom, ${txtColor}, ${txtColor2})`,
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
      } : {
        color: txtColor,
      }),
      // Shadow Effect
      filter: `drop-shadow(${sOffset * previewScale}px ${sOffset * previewScale}px ${sBlur * previewScale}px ${sColor})`
    };
  };

  return (
    <div className="flex flex-col h-screen max-h-screen overflow-hidden bg-slate-950 text-slate-100">
      <header className="h-14 flex items-center justify-between px-6 border-b border-slate-800 bg-slate-900/80 backdrop-blur-md z-50">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
          </div>
          <span className="font-black tracking-tighter text-xl bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">THUMBNAIL.AI</span>
          <span className="hidden sm:inline-block px-2 py-0.5 rounded text-[10px] bg-slate-800 text-slate-400 font-bold border border-slate-700">STUDIO PRO</span>
        </div>

        <div className="flex items-center gap-4">
          <button onClick={() => setConfig(DEFAULT_CONFIG)} className="text-xs font-bold text-slate-400 hover:text-white transition-colors">RESET</button>
          <div className="h-4 w-px bg-slate-700 mx-2" />
          <button 
            onClick={downloadThumbnail} 
            className="flex items-center gap-2 px-4 py-1.5 bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-black rounded-full transition-all shadow-lg shadow-indigo-500/20 active:scale-95"
          >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
            EXPORT IMAGE
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-[306px] border-r border-slate-800 bg-slate-900/40 flex flex-col overflow-hidden">
          <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <span className="w-5 h-5 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-[10px] font-bold text-slate-400">2</span>
              <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Design Editor</h3>
            </div>
            <EditorControls config={config} onChange={updateConfig} />
          </div>
        </aside>

        <section className="flex-1 bg-slate-950 workspace-bg flex flex-col items-center p-6 relative overflow-y-auto custom-scrollbar">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-indigo-500/[0.03] blur-[150px] rounded-full pointer-events-none" />

          <div className="w-full max-w-[1000px] space-y-8 z-10">

            <div className="bg-slate-900/60 border border-slate-800 rounded-3xl p-6 shadow-2xl backdrop-blur-md">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <span className="w-6 h-6 rounded-full bg-indigo-600 flex items-center justify-center text-[11px] font-black text-white shadow-lg shadow-indigo-500/30">1</span>
                  <h3 className="text-xs font-black text-slate-300 uppercase tracking-widest">Concept Ideation</h3>
                </div>
                <div className="flex gap-2">
                  {['Vietnamese', 'English'].map((lang) => (
                    <button
                      key={lang}
                      onClick={() => setLanguage(lang)}
                      className={`px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all border ${language === lang ? 'bg-indigo-600/10 border-indigo-500 text-indigo-400' : 'bg-slate-800/50 border-slate-700 text-slate-500'}`}
                    >
                      {lang === 'Vietnamese' ? 'Tiếng Việt' : 'English'}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex flex-col md:flex-row gap-4">
                <div className="flex-1">
                  <textarea
                    placeholder="Paste script or describe your video topic here..."
                    className="w-full h-24 bg-slate-950/50 border border-slate-800 rounded-2xl p-4 text-sm focus:ring-1 focus:ring-indigo-500 outline-none transition-all resize-none placeholder:text-slate-700"
                    value={script}
                    onChange={(e) => setScript(e.target.value)}
                  />
                </div>
                <div className="flex flex-col gap-3 min-w-[200px]">
                  <button
                    onClick={handleAnalyze}
                    disabled={status === AppStatus.ANALYZING || !script}
                    className="flex-1 py-3 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 font-black rounded-2xl transition-all shadow-xl shadow-indigo-500/10 text-xs tracking-tight flex items-center justify-center gap-2"
                  >
                    {status === AppStatus.ANALYZING ? (
                      <>
                        <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        ANALYZING...
                      </>
                    ) : 'GENERATE CONCEPTS'}
                  </button>
                  <button 
                    onClick={triggerUpload} 
                    className="py-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all border border-slate-700 flex items-center justify-center gap-2 text-xs font-bold text-slate-300 group"
                  >
                    <svg className="w-4 h-4 text-slate-400 group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    UPLOAD BG
                  </button>
                  <input type="file" ref={fileInputRef} onChange={handleImageUpload} className="hidden" accept="image/*" />
                </div>
              </div>
            </div>

            <div className="relative group">
              <div 
                ref={containerRef}
                className={`canvas-container w-full select-none border border-slate-800/60 overflow-hidden shadow-indigo-500/5 ${config.imageUrl ? '' : 'bg-slate-900'}`}
                style={{ backgroundImage: config.imageUrl ? `url(${config.imageUrl})` : 'none' }}
              >
                {!config.imageUrl && (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 opacity-50 pointer-events-none">
                    <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <p className="text-[12px] font-black tracking-[0.3em] uppercase">Stage Ready for AI Artwork</p>
                  </div>
                )}

                <div className="absolute inset-0 bg-black pointer-events-none" style={{ opacity: config.overlayOpacity / 100 }} />

                <div 
                  ref={textRef}
                  onMouseDown={handleMouseDown}
                  className={`absolute flex flex-col leading-[1.0] uppercase pointer-events-auto transition-all cursor-grab active:cursor-grabbing group p-4 rounded-lg border-2 border-transparent hover:border-indigo-500/30 hover:bg-white/5 ${isDragging ? 'scale-105 z-50 !border-indigo-500/50 bg-white/10' : ''}`}
                  style={{ 
                    left: `${config.textPosition.x}%`,
                    top: `${config.textPosition.y}%`, 
                    transform: 'translate(-50%, -50%)',
                    fontFamily: config.fontFamily,
                    textAlign: 'center'
                  }}
                >
                  <div className="absolute -top-7 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-all bg-indigo-600 text-[8px] font-black px-3 py-1 rounded-full uppercase tracking-widest text-white whitespace-nowrap shadow-lg">
                     Reposition Text
                  </div>

                  <span 
                    className="block whitespace-nowrap" 
                    style={getTextStyle('line1')}
                  >
                    {config.line1Text}
                  </span>
                  {config.showLine2 && (
                    <span 
                      className="block whitespace-nowrap" 
                      style={getTextStyle('line2')}
                    >
                      {config.line2Text}
                    </span>
                  )}
                </div>

                {status === AppStatus.GENERATING_IMAGE && (
                  <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center text-center p-8 z-[60]">
                    <div className="relative">
                      <div className="w-16 h-16 border-2 border-indigo-500/20 rounded-full mb-4"></div>
                      <div className="absolute top-0 left-0 w-16 h-16 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                    </div>
                    <p className="text-white font-black tracking-[0.2em] text-[11px] uppercase animate-pulse">Rendering AI Masterpiece</p>
                  </div>
                )}
              </div>

              <div className="mt-4 flex justify-between items-center bg-slate-900/40 p-4 rounded-3xl border border-slate-800">
                <div className="flex items-center gap-6">
                   <div className="flex items-center gap-3">
                      <div className="w-2.5 h-2.5 rounded-full bg-indigo-500 animate-ping" />
                      <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Interactive Canvas</span>
                   </div>
                   <div className="h-5 w-px bg-slate-800" />
                   <span className="text-[10px] text-slate-500 uppercase font-black tracking-wider italic">Pro Tip: Drag text to adjust the visual focal point</span>
                </div>
                <div className="flex gap-2">
                   <button onClick={() => updateConfig({ textPosition: { x: 50, y: 50 } })} className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-[10px] font-black text-slate-300 rounded-xl transition-all border border-slate-700 active:scale-95 uppercase tracking-tighter">Center Text</button>
                </div>
              </div>
            </div>
          </div>
        </section>

        <aside className="w-[300px] border-l border-slate-800 bg-slate-900/60 flex flex-col overflow-hidden">
          <div className="p-5 border-b border-slate-800 bg-slate-900/40">
            <h3 className="text-xs font-black text-indigo-400 uppercase tracking-widest flex items-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              AI Assistant
            </h3>
          </div>

          <div className="flex-1 overflow-y-auto custom-scrollbar p-5">
            {suggestions ? (
              <div className="space-y-8">
                <div>
                  <h4 className="text-[10px] font-black text-slate-500 uppercase mb-4 tracking-wider">Suggested Viral Titles</h4>
                  <div className="grid gap-2">
                    {suggestions.titles.map((title, i) => (
                      <button 
                        key={i} 
                        onClick={() => applyTitleSuggestion(title)} 
                        className="w-full text-left p-3 rounded-xl bg-slate-950/50 border border-slate-800 hover:border-indigo-500 hover:bg-indigo-500/5 transition-all group"
                      >
                        <span className="block text-[11px] font-black uppercase text-slate-300 group-hover:text-white leading-relaxed">{title}</span>
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <h4 className="text-[10px] font-black text-slate-500 uppercase mb-4 tracking-wider">Visual Compositions</h4>
                  <div className="space-y-4">
                    {suggestions.imagePrompts.map((p, i) => (
                      <div key={i} className="flex flex-col gap-2 p-3 rounded-xl bg-slate-950/50 border border-slate-800">
                        <textarea
                          value={p}
                          onChange={(e) => updatePrompt(i, e.target.value)}
                          className="w-full bg-transparent text-[10px] text-slate-400 leading-relaxed min-h-[70px] outline-none resize-none border-none p-0"
                        />
                        <div className="flex gap-2 pt-2 border-t border-slate-900">
                          <button
                            onClick={() => handleCopyPrompt(p, i)}
                            className="flex-1 py-1.5 rounded-lg bg-slate-800 hover:bg-slate-700 text-[9px] font-bold text-slate-400 transition-colors"
                          >
                            {copyStatus === i ? 'COPIED' : 'COPY'}
                          </button>
                          <button
                            onClick={() => handleGenerateImage(p)}
                            disabled={status === AppStatus.GENERATING_IMAGE}
                            className="flex-[2] py-1.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-[9px] font-black text-white transition-all shadow-md shadow-indigo-500/10"
                          >
                            {status === AppStatus.GENERATING_IMAGE ? 'GENERATING...' : 'PAINT SCENE'}
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-center px-4">
                <div className="w-16 h-16 rounded-full bg-slate-800/50 flex items-center justify-center mb-6 border border-slate-700 border-dashed">
                  <svg className="w-6 h-6 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
                </div>
                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] leading-loose">Waiting for project description in Step 1</p>
              </div>
            )}
          </div>
        </aside>
      </main>

      {error && (
        <div className="fixed bottom-6 right-6 bg-red-600 text-white px-6 py-4 rounded-2xl shadow-2xl z-[100] border-2 border-white/20 font-bold flex items-center gap-3">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          {error}
        </div>
      )}
    </div>
  );
};

export default App;

export interface SuggestionResponse {
  titles: string[];
  imagePrompts: string[];
}

export interface GraphicElement {
  id: string;
  type: 'icon' | 'shape';
  path: string;
  x: number;
  y: number;
  size: number;
  color: string;
  rotation: number;
}

export interface ThumbnailConfig {
  imageUrl: string | null;
  fontFamily: string;
  textPosition: { x: number; y: number };
  overlayOpacity: number;
  graphics: GraphicElement[];

  // Line 1 Styling
  line1Text: string;
  line1Color: string;
  line1Color2: string; // For gradient
  line1IsGradient: boolean;
  line1StrokeColor: string;
  line1FontSize: number;
  line1StrokeWidth: number;
  line1Align: 'left' | 'center' | 'right';
  line1Bold: boolean;
  line1Italic: boolean;
  line1Underline: boolean;
  line1ShadowBlur: number;
  line1ShadowOffset: number;
  line1ShadowColor: string;

  // Line 2 Styling
  line2Text: string;
  line2Color: string;
  line2Color2: string; // For gradient
  line2IsGradient: boolean;
  line2StrokeColor: string;
  line2FontSize: number;
  line2StrokeWidth: number;
  line2Align: 'left' | 'center' | 'right';
  line2Bold: boolean;
  line2Italic: boolean;
  line2Underline: boolean;
  line2ShadowBlur: number;
  line2ShadowOffset: number;
  line2ShadowColor: string;

  showLine2: boolean;
}

export enum AppStatus {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  GENERATING_IMAGE = 'GENERATING_IMAGE',
  READY = 'READY'
}

import React from 'react';
import { ThumbnailConfig } from '../types';
import { FONT_FAMILIES, COLOR_PALETTES } from '../constants';

interface EditorControlsProps {
  config: ThumbnailConfig;
  onChange: (updates: Partial<ThumbnailConfig>) => void;
}

export const EditorControls: React.FC<EditorControlsProps> = ({ config, onChange }) => {
  const SectionHeader = ({ title }: { title: string }) => (
    <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">{title}</h4>
  );

  const ValueDisplay = ({ value, unit = '' }: { value: number | string, unit?: string }) => (
    <span className="text-[15px] text-indigo-400 font-mono font-bold leading-none">
      {value}{unit}
    </span>
  );

  const AlignmentControl = ({ value, onSelect }: { value: string, onSelect: (val: any) => void }) => (
    <div className="flex bg-slate-900 p-1 rounded-lg gap-1 border border-slate-700">
      {(['left', 'center', 'right'] as const).map((align) => (
        <button
          key={align}
          onClick={() => onSelect(align)}
          className={`flex-1 flex items-center justify-center p-1 rounded transition-all ${value === align ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
        >
          {align === 'left' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h10M4 18h16" /></svg>}
          {align === 'center' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M7 12h10M4 18h16" /></svg>}
          {align === 'right' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M10 12h10M4 18h16" /></svg>}
        </button>
      ))}
    </div>
  );

  const FontStyleControl = ({ bold, italic, underline, onBold, onItalic, onUnderline }: { bold: boolean, italic: boolean, underline: boolean, onBold: () => void, onItalic: () => void, onUnderline: () => void }) => (
    <div className="flex bg-slate-900 p-1 rounded-lg gap-1 border border-slate-700">
      <button
        onClick={onBold}
        className={`flex-1 flex items-center justify-center p-1 rounded transition-all font-black text-sm ${bold ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
      >
        B
      </button>
      <button
        onClick={onItalic}
        className={`flex-1 flex items-center justify-center p-1 rounded transition-all font-serif italic text-sm ${italic ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
      >
        I
      </button>
      <button
        onClick={onUnderline}
        className={`flex-1 flex items-center justify-center p-1 rounded transition-all underline font-bold text-sm ${underline ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
      >
        U
      </button>
    </div>
  );

  const ColorSelector = ({ selected, onSelect, label }: { selected: string, onSelect: (color: string) => void, label: string }) => (
    <div className="space-y-1.5">
      <label className="text-[8px] text-slate-500 font-bold uppercase tracking-wider block">{label}</label>
      <div className="flex flex-wrap gap-1">
        {COLOR_PALETTES.slice(0, 8).map((p) => (
          <button
            key={p.name}
            onClick={() => onSelect(p.color)}
            className={`w-4 h-4 rounded-sm border transition-all ${selected === p.color ? 'ring-1 ring-indigo-500 ring-offset-1 ring-offset-slate-900 border-white' : 'border-slate-800 hover:border-slate-600'}`}
            style={{ backgroundColor: p.color }}
            title={p.name}
          />
        ))}
      </div>
    </div>
  );

  const Slider = ({ label, value, min, max, step = 1, onChange, unit = '' }: { label: string, value: number, min: number, max: number, step?: number, onChange: (val: number) => void, unit?: string }) => (
    <div className="space-y-1.5">
      <div className="flex justify-between items-end">
        <label className="text-[9px] text-slate-400 font-bold uppercase tracking-wider">{label}</label>
        <ValueDisplay value={value} unit={unit} />
      </div>
      <input
        type="range" min={min} max={max} step={step} value={value}
        onChange={(e) => onChange(parseFloat(e.target.value))}
        className="w-full h-1 bg-slate-800 rounded appearance-none accent-indigo-500 cursor-pointer"
      />
    </div>
  );

  return (
    <div className="flex flex-col gap-6">

      {/* Typography Section */}
      <section className="bg-slate-950/40 p-4 rounded-xl border border-slate-800/60">
        <SectionHeader title="Global Style" />
        <div className="space-y-4">
          <div>
            <label className="text-[9px] text-slate-400 font-bold uppercase mb-1.5 block tracking-wider">Primary Font</label>
            <select
              value={config.fontFamily}
              onChange={(e) => onChange({ fontFamily: e.target.value })}
              className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2 text-white text-xs font-bold outline-none focus:border-indigo-500 transition-all"
            >
              {FONT_FAMILIES.map((f) => (
                <option key={f.name} value={f.value} style={{ fontFamily: f.value }}>{f.name}</option>
              ))}
            </select>
          </div>

          <Slider 
            label="Background Dimming" 
            value={config.overlayOpacity} 
            min={0} max={100} 
            onChange={(v) => onChange({ overlayOpacity: v })} 
            unit="%" 
          />
        </div>
      </section>

      {/* Line 1 Section */}
      <section className="bg-slate-950/40 p-4 rounded-xl border border-slate-800/60">
        <div className="flex justify-between items-center mb-3">
          <SectionHeader title="Line One" />
          <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse" />
        </div>
        <input
          type="text"
          value={config.line1Text}
          onChange={(e) => onChange({ line1Text: e.target.value })}
          className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2.5 text-white font-bold uppercase text-xs mb-4 outline-none focus:border-indigo-500 transition-all placeholder:text-slate-600"
          placeholder="Main Hook..."
        />

        <div className="flex flex-col gap-4 mb-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-[9px] text-slate-400 font-bold uppercase mb-1.5 block tracking-wider">Align</label>
              <AlignmentControl value={config.line1Align} onSelect={(val) => onChange({ line1Align: val })} />
            </div>
            <div>
              <label className="text-[9px] text-slate-400 font-bold uppercase mb-1.5 block tracking-wider">Style</label>
              <FontStyleControl 
                bold={config.line1Bold}
                italic={config.line1Italic} 
                underline={config.line1Underline} 
                onBold={() => onChange({ line1Bold: !config.line1Bold })}
                onItalic={() => onChange({ line1Italic: !config.line1Italic })}
                onUnderline={() => onChange({ line1Underline: !config.line1Underline })}
              />
            </div>
          </div>

          <div className="bg-slate-900/40 p-3 rounded-lg border border-slate-800/60">
            <div className="flex items-center justify-between mb-2">
              <label className="text-[9px] text-slate-400 font-bold uppercase tracking-wider">Color Gradient</label>
              <button 
                onClick={() => onChange({ line1IsGradient: !config.line1IsGradient })}
                className={`px-2 py-0.5 rounded text-[8px] font-black uppercase transition-all ${config.line1IsGradient ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}
              >
                {config.line1IsGradient ? 'On' : 'Off'}
              </button>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <ColorSelector 
                label={config.line1IsGradient ? "Color Start" : "Text Color"} 
                selected={config.line1Color} 
                onSelect={(color) => onChange({ line1Color: color })} 
              />
              {config.line1IsGradient && (
                <ColorSelector 
                  label="Color End" 
                  selected={config.line1Color2} 
                  onSelect={(color) => onChange({ line1Color2: color })} 
                />
              )}
              <ColorSelector 
                label="Stroke Color" 
                selected={config.line1StrokeColor} 
                onSelect={(color) => onChange({ line1StrokeColor: color })} 
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <Slider label="Size" value={config.line1FontSize} min={20} max={180} onChange={(v) => onChange({ line1FontSize: v })} />
            <Slider label="Stroke" value={config.line1StrokeWidth} min={0} max={10} step={0.5} onChange={(v) => onChange({ line1StrokeWidth: v })} />
          </div>

          <div className="bg-slate-900/40 p-3 rounded-lg border border-slate-800/60 space-y-3">
             <SectionHeader title="Drop Shadow / Glow" />
             <div className="grid grid-cols-2 gap-4">
               <Slider label="Blur" value={config.line1ShadowBlur} min={0} max={30} onChange={(v) => onChange({ line1ShadowBlur: v })} />
               <Slider label="Dist" value={config.line1ShadowOffset} min={0} max={20} onChange={(v) => onChange({ line1ShadowOffset: v })} />
             </div>
             <ColorSelector label="Shadow Color" selected={config.line1ShadowColor} onSelect={(c) => onChange({ line1ShadowColor: c })} />
          </div>
        </div>
      </section>

      {/* Line 2 Section */}
      <section className="bg-slate-950/40 p-4 rounded-xl border border-slate-800/60">
        <div className="flex justify-between items-center mb-3">
          <SectionHeader title="Line Two" />
          <label className="relative inline-flex items-center cursor-pointer">
            <input 
              type="checkbox" 
              checked={config.showLine2} 
              onChange={(e) => onChange({ showLine2: e.target.checked })} 
              className="sr-only peer"
            />
            <div className="w-8 h-4 bg-slate-800 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-3 after:w-4 after:transition-all peer-checked:bg-indigo-600"></div>
          </label>
        </div>

        {config.showLine2 && (
          <div className="space-y-4 pt-2 transition-all">
            <input
              type="text"
              value={config.line2Text}
              onChange={(e) => onChange({ line2Text: e.target.value })}
              className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2.5 text-white font-bold uppercase text-xs mb-4 outline-none focus:border-indigo-500 transition-all placeholder:text-slate-600"
              placeholder="Secondary Text..."
            />

            <div className="flex flex-col gap-4 mb-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[9px] text-slate-400 font-bold uppercase mb-1.5 block tracking-wider">Align</label>
                  <AlignmentControl value={config.line2Align} onSelect={(val) => onChange({ line2Align: val })} />
                </div>
                <div>
                  <label className="text-[9px] text-slate-400 font-bold uppercase mb-1.5 block tracking-wider">Style</label>
                  <FontStyleControl 
                    bold={config.line2Bold}
                    italic={config.line2Italic} 
                    underline={config.line2Underline} 
                    onBold={() => onChange({ line2Bold: !config.line2Bold })}
                    onItalic={() => onChange({ line2Italic: !config.line2Italic })}
                    onUnderline={() => onChange({ line2Underline: !config.line2Underline })}
                  />
                </div>
              </div>

              <div className="bg-slate-900/40 p-3 rounded-lg border border-slate-800/60">
                <div className="flex items-center justify-between mb-2">
                  <label className="text-[9px] text-slate-400 font-bold uppercase tracking-wider">Color Gradient</label>
                  <button 
                    onClick={() => onChange({ line2IsGradient: !config.line2IsGradient })}
                    className={`px-2 py-0.5 rounded text-[8px] font-black uppercase transition-all ${config.line2IsGradient ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}
                  >
                    {config.line2IsGradient ? 'On' : 'Off'}
                  </button>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <ColorSelector 
                    label={config.line2IsGradient ? "Color Start" : "Text Color"} 
                    selected={config.line2Color} 
                    onSelect={(color) => onChange({ line2Color: color })} 
                  />
                  {config.line2IsGradient && (
                    <ColorSelector 
                      label="Color End" 
                      selected={config.line2Color2} 
                      onSelect={(color) => onChange({ line2Color2: color })} 
                    />
                  )}
                  <ColorSelector 
                    label="Stroke Color" 
                    selected={config.line2StrokeColor} 
                    onSelect={(color) => onChange({ line2StrokeColor: color })} 
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <Slider label="Size" value={config.line2FontSize} min={20} max={180} onChange={(v) => onChange({ line2FontSize: v })} />
                <Slider label="Stroke" value={config.line2StrokeWidth} min={0} max={10} step={0.5} onChange={(v) => onChange({ line2StrokeWidth: v })} />
              </div>

              <div className="bg-slate-900/40 p-3 rounded-lg border border-slate-800/60 space-y-3">
                 <SectionHeader title="Drop Shadow / Glow" />
                 <div className="grid grid-cols-2 gap-4">
                   <Slider label="Blur" value={config.line2ShadowBlur} min={0} max={30} onChange={(v) => onChange({ line2ShadowBlur: v })} />
                   <Slider label="Dist" value={config.line2ShadowOffset} min={0} max={20} onChange={(v) => onChange({ line2ShadowOffset: v })} />
                 </div>
                 <ColorSelector label="Shadow Color" selected={config.line2ShadowColor} onSelect={(c) => onChange({ line2ShadowColor: c })} />
              </div>
            </div>
          </div>
        )}
      </section>
    </div>
  );
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppStatus, SuggestionResponse, ThumbnailConfig } from './types';
import { DEFAULT_CONFIG } from './constants';
import { analyzeScript, generateThumbnailImage } from './services/geminiService';
import { EditorControls } from './components/EditorControls';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [script, setScript] = useState('');
  const [language, setLanguage] = useState('Vietnamese');
  const [suggestions, setSuggestions] = useState<SuggestionResponse | null>(null);
  const [config, setConfig] = useState<ThumbnailConfig>(DEFAULT_CONFIG);
  const [error, setError] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [copyStatus, setCopyStatus] = useState<number | null>(null);
  const [previewScale, setPreviewScale] = useState(1);

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const updateScale = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth;
        setPreviewScale(width / 1280);
      }
    };
    updateScale();
    window.addEventListener('resize', updateScale);
    return () => window.removeEventListener('resize', updateScale);
  }, []);

  const handleAnalyze = async () => {
    if (!script.trim()) return;
    setStatus(AppStatus.ANALYZING);
    setError(null);
    try {
      const result = await analyzeScript(script, language);
      setSuggestions(result);
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to analyze script. Please try again.');
      setStatus(AppStatus.IDLE);
    }
  };

  const handleGenerateImage = async (prompt: string) => {
    setStatus(AppStatus.GENERATING_IMAGE);
    setError(null);
    try {
      const url = await generateThumbnailImage(prompt);
      setConfig(prev => ({ ...prev, imageUrl: url }));
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to generate image. Please try again.');
      setStatus(AppStatus.READY);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, imageUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  const applyTitleSuggestion = (title: string) => {
    const words = title.split(' ');
    if (words.length > 3) {
      const middle = Math.ceil(words.length / 2);
      setConfig(prev => ({
        ...prev,
        line1Text: words.slice(0, middle).join(' ').toUpperCase(),
        line2Text: words.slice(middle).join(' ').toUpperCase(),
        showLine2: true
      }));
    } else {
      setConfig(prev => ({
        ...prev,
        line1Text: title.toUpperCase(),
        showLine2: false
      }));
    }
  };

  const handleCopyPrompt = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopyStatus(index);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const updatePrompt = (index: number, newText: string) => {
    if (!suggestions) return;
    const newPrompts = [...suggestions.imagePrompts];
    newPrompts[index] = newText;
    setSuggestions({ ...suggestions, imagePrompts: newPrompts });
  };

  const updateConfig = (updates: Partial<ThumbnailConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!textRef.current || !containerRef.current) return;
    setIsDragging(true);
    const textRect = textRef.current.getBoundingClientRect();
    const offsetX = e.clientX - (textRect.left + textRect.width / 2);
    const offsetY = e.clientY - (textRect.top + textRect.height / 2);
    setDragOffset({ x: offsetX, y: offsetY });
    e.stopPropagation();
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const adjustedX = e.clientX - dragOffset.x;
    const adjustedY = e.clientY - dragOffset.y;
    const x = ((adjustedX - rect.left) / rect.width) * 100;
    const y = ((adjustedY - rect.top) / rect.height) * 100;
    updateConfig({ textPosition: { x: Math.max(0, Math.min(100, x)), y: Math.max(0, Math.min(100, y)) } });
  }, [isDragging, dragOffset]);

  const handleMouseUp = useCallback(() => setIsDragging(false), []);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'grabbing';
    } else {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = '';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, handleMouseMove, handleMouseUp]);

  const downloadThumbnail = () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1280;
    canvas.height = 720;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
        ctx.clearRect(0, 0, 1280, 720);
        ctx.drawImage(img, 0, 0, 1280, 720);
        ctx.fillStyle = `rgba(0, 0, 0, ${config.overlayOpacity / 100})`;
        ctx.fillRect(0, 0, 1280, 720);

        const tx = (config.textPosition.x / 100) * 1280;
        const ty = (config.textPosition.y / 100) * 720;
        ctx.textBaseline = 'middle';
        ctx.lineJoin = 'round';

        const drawLine = (text: string, color: string, color2: string, isGradient: boolean, fontSize: number, strokeWidth: number, strokeColor: string, align: 'left' | 'center' | 'right', bold: boolean, italic: boolean, underline: boolean, shadowBlur: number, shadowOffset: number, shadowColor: string, y: number) => {
            const fontStyle = italic ? 'italic' : '';
            const fontWeight = bold ? 'bold' : 'normal';
            ctx.save();
            ctx.font = `${fontStyle} ${fontWeight} ${fontSize}px ${config.fontFamily}`; 
            ctx.textAlign = align;

            // Apply Shadow
            ctx.shadowColor = shadowColor;
            ctx.shadowBlur = shadowBlur;
            ctx.shadowOffsetX = shadowOffset;
            ctx.shadowOffsetY = shadowOffset;

            // Gradient handle
            if (isGradient) {
              const gradient = ctx.createLinearGradient(tx, y - fontSize/2, tx, y + fontSize/2);
              gradient.addColorStop(0, color);
              gradient.addColorStop(1, color2);
              ctx.fillStyle = gradient;
            } else {
              ctx.fillStyle = color;
            }

            // Stroke
            if (strokeWidth > 0) {
              ctx.lineWidth = strokeWidth * 2; 
              ctx.strokeStyle = strokeColor;
              ctx.strokeText(text.toUpperCase(), tx, y);
            }

            // Fill
            ctx.fillText(text.toUpperCase(), tx, y);

            if (underline) {
              const textWidth = ctx.measureText(text.toUpperCase()).width;
              let lineXStart = tx;
              if (align === 'center') lineXStart = tx - textWidth / 2;
              else if (align === 'right') lineXStart = tx - textWidth;
              const lineY = y + fontSize * 0.45;
              ctx.beginPath();
              ctx.moveTo(lineXStart, lineY);
              ctx.lineTo(lineXStart + textWidth, lineY);
              ctx.lineWidth = fontSize * 0.08;
              ctx.strokeStyle = color;
              ctx.stroke();
            }
            ctx.restore();
        };

        if (config.showLine2) {
            drawLine(config.line1Text, config.line1Color, config.line1Color2, config.line1IsGradient, config.line1FontSize, config.line1StrokeWidth, config.line1StrokeColor, config.line1Align, config.line1Bold, config.line1Italic, config.line1Underline, config.line1ShadowBlur, config.line1ShadowOffset, config.line1ShadowColor, ty - (config.line1FontSize / 2));
            drawLine(config.line2Text, config.line2Color, config.line2Color2, config.line2IsGradient, config.line2FontSize, config.line2StrokeWidth, config.line2StrokeColor, config.line2Align, config.line2Bold, config.line2Italic, config.line2Underline, config.line2ShadowBlur, config.line2ShadowOffset, config.line2ShadowColor, ty + (config.line2FontSize / 2));
        } else {
            drawLine(config.line1Text, config.line1Color, config.line1Color2, config.line1IsGradient, config.line1FontSize, config.line1StrokeWidth, config.line1StrokeColor, config.line1Align, config.line1Bold, config.line1Italic, config.line1Underline, config.line1ShadowBlur, config.line1ShadowOffset, config.line1ShadowColor, ty);
        }

      const link = document.createElement('a');
      link.download = `thumbnail-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    };
    img.src = config.imageUrl || 'https://picsum.photos/1280/720?grayscale';
  };

  const getTextStyle = (line: 'line1' | 'line2') => {
    const isLine1 = line === 'line1';
    const c = config;
    const txtColor = isLine1 ? c.line1Color : c.line2Color;
    const txtColor2 = isLine1 ? c.line1Color2 : c.line2Color2;
    const isGrad = isLine1 ? c.line1IsGradient : c.line2IsGradient;
    const sColor = isLine1 ? c.line1ShadowColor : c.line2ShadowColor;
    const sBlur = isLine1 ? c.line1ShadowBlur : c.line2ShadowBlur;
    const sOffset = isLine1 ? c.line1ShadowOffset : c.line2ShadowOffset;
    const strokeW = isLine1 ? c.line1StrokeWidth : c.line2StrokeWidth;
    const strokeC = isLine1 ? c.line1StrokeColor : c.line2StrokeColor;
    const align = isLine1 ? c.line1Align : c.line2Align;
    const fSize = isLine1 ? c.line1FontSize : c.line2FontSize;
    const bold = isLine1 ? c.line1Bold : c.line2Bold;
    const italic = isLine1 ? c.line1Italic : c.line2Italic;
    const underline = isLine1 ? c.line1Underline : c.line2Underline;

    return {
      fontSize: `${fSize * previewScale}px`,
      WebkitTextStroke: `${strokeW * previewScale}px ${strokeC}`,
      textAlign: align as any,
      fontWeight: bold ? 'bold' : 'normal',
      fontStyle: italic ? 'italic' : 'normal',
      textDecoration: underline ? 'underline' : 'none',
      width: '100%',
      // Gradient Text Logic
      ...(isGrad ? {
        backgroundImage: `linear-gradient(to bottom, ${txtColor}, ${txtColor2})`,
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
      } : {
        color: txtColor,
      }),
      // Shadow Effect
      filter: `drop-shadow(${sOffset * previewScale}px ${sOffset * previewScale}px ${sBlur * previewScale}px ${sColor})`
    };
  };

  return (
    <div className="flex flex-col h-screen max-h-screen overflow-hidden bg-slate-950 text-slate-100">
      <header className="h-14 flex items-center justify-between px-6 border-b border-slate-800 bg-slate-900/80 backdrop-blur-md z-50">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
          </div>
          <span className="font-black tracking-tighter text-xl bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">THUMBNAIL.AI</span>
          <span className="hidden sm:inline-block px-2 py-0.5 rounded text-[10px] bg-slate-800 text-slate-400 font-bold border border-slate-700">STUDIO PRO</span>
        </div>

        <div className="flex items-center gap-4">
          <button onClick={() => setConfig(DEFAULT_CONFIG)} className="text-xs font-bold text-slate-400 hover:text-white transition-colors">RESET</button>
          <div className="h-4 w-px bg-slate-700 mx-2" />
          <button 
            onClick={downloadThumbnail} 
            className="flex items-center gap-2 px-4 py-1.5 bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-black rounded-full transition-all shadow-lg shadow-indigo-500/20 active:scale-95"
          >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
            EXPORT IMAGE
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-[306px] border-r border-slate-800 bg-slate-900/40 flex flex-col overflow-hidden">
          <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <span className="w-5 h-5 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-[10px] font-bold text-slate-400">2</span>
              <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Design Editor</h3>
            </div>
            <EditorControls config={config} onChange={updateConfig} />
          </div>
        </aside>

        <section className="flex-1 bg-slate-950 workspace-bg flex flex-col items-center p-6 relative overflow-y-auto custom-scrollbar">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-indigo-500/[0.03] blur-[150px] rounded-full pointer-events-none" />

          <div className="w-full max-w-[1000px] space-y-8 z-10">

            <div className="bg-slate-900/60 border border-slate-800 rounded-3xl p-6 shadow-2xl backdrop-blur-md">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <span className="w-6 h-6 rounded-full bg-indigo-600 flex items-center justify-center text-[11px] font-black text-white shadow-lg shadow-indigo-500/30">1</span>
                  <h3 className="text-xs font-black text-slate-300 uppercase tracking-widest">Concept Ideation</h3>
                </div>
                <div className="flex gap-2">
                  {['Vietnamese', 'English'].map((lang) => (
                    <button
                      key={lang}
                      onClick={() => setLanguage(lang)}
                      className={`px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all border ${language === lang ? 'bg-indigo-600/10 border-indigo-500 text-indigo-400' : 'bg-slate-800/50 border-slate-700 text-slate-500'}`}
                    >
                      {lang === 'Vietnamese' ? 'Tiếng Việt' : 'English'}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex flex-col md:flex-row gap-4">
                <div className="flex-1">
                  <textarea
                    placeholder="Paste script or describe your video topic here..."
                    className="w-full h-24 bg-slate-950/50 border border-slate-800 rounded-2xl p-4 text-sm focus:ring-1 focus:ring-indigo-500 outline-none transition-all resize-none placeholder:text-slate-700"
                    value={script}
                    onChange={(e) => setScript(e.target.value)}
                  />
                </div>
                <div className="flex flex-col gap-3 min-w-[200px]">
                  <button
                    onClick={handleAnalyze}
                    disabled={status === AppStatus.ANALYZING || !script}
                    className="flex-1 py-3 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 font-black rounded-2xl transition-all shadow-xl shadow-indigo-500/10 text-xs tracking-tight flex items-center justify-center gap-2"
                  >
                    {status === AppStatus.ANALYZING ? (
                      <>
                        <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        ANALYZING...
                      </>
                    ) : 'GENERATE CONCEPTS'}
                  </button>
                  <button 
                    onClick={triggerUpload} 
                    className="py-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all border border-slate-700 flex items-center justify-center gap-2 text-xs font-bold text-slate-300 group"
                  >
                    <svg className="w-4 h-4 text-slate-400 group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    UPLOAD BG
                  </button>
                  <input type="file" ref={fileInputRef} onChange={handleImageUpload} className="hidden" accept="image/*" />
                </div>
              </div>
            </div>

            <div className="relative group">
              <div 
                ref={containerRef}
                className={`canvas-container w-full select-none border border-slate-800/60 overflow-hidden shadow-indigo-500/5 ${config.imageUrl ? '' : 'bg-slate-900'}`}
                style={{ backgroundImage: config.imageUrl ? `url(${config.imageUrl})` : 'none' }}
              >
                {!config.imageUrl && (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 opacity-50 pointer-events-none">
                    <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <p className="text-[12px] font-black tracking-[0.3em] uppercase">Stage Ready for AI Artwork</p>
                  </div>
                )}

                <div className="absolute inset-0 bg-black pointer-events-none" style={{ opacity: config.overlayOpacity / 100 }} />

                <div 
                  ref={textRef}
                  onMouseDown={handleMouseDown}
                  className={`absolute flex flex-col leading-[1.0] uppercase pointer-events-auto transition-all cursor-grab active:cursor-grabbing group p-4 rounded-lg border-2 border-transparent hover:border-indigo-500/30 hover:bg-white/5 ${isDragging ? 'scale-105 z-50 !border-indigo-500/50 bg-white/10' : ''}`}
                  style={{ 
                    left: `${config.textPosition.x}%`,
                    top: `${config.textPosition.y}%`, 
                    transform: 'translate(-50%, -50%)',
                    fontFamily: config.fontFamily,
                    textAlign: 'center'
                  }}
                >
                  <div className="absolute -top-7 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-all bg-indigo-600 text-[8px] font-black px-3 py-1 rounded-full uppercase tracking-widest text-white whitespace-nowrap shadow-lg">
                     Reposition Text
                  </div>

                  <span 
                    className="block whitespace-nowrap" 
                    style={getTextStyle('line1')}
                  >
                    {config.line1Text}
                  </span>
                  {config.showLine2 && (
                    <span 
                      className="block whitespace-nowrap" 
                      style={getTextStyle('line2')}
                    >
                      {config.line2Text}
                    </span>
                  )}
                </div>

                {status === AppStatus.GENERATING_IMAGE && (
                  <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center text-center p-8 z-[60]">
                    <div className="relative">
                      <div className="w-16 h-16 border-2 border-indigo-500/20 rounded-full mb-4"></div>
                      <div className="absolute top-0 left-0 w-16 h-16 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
