              <div className="w-full space-y-4 text-left">
                <div className="flex gap-4 p-4 bg-slate-800/50 rounded-2xl border border-slate-700/50">
                  <div className="w-8 h-8 rounded-full bg-indigo-600 flex-shrink-0 flex items-center justify-center text-xs font-black">1</div>
                  <p className="text-xs text-slate-300">Trên thanh địa chỉ trình duyệt (Chrome/Edge), nhấn biểu tượng <b>[Install]</b> (hình màn hình kèm mũi tên xuống).</p>
                </div>
                <div className="flex gap-4 p-4 bg-slate-800/50 rounded-2xl border border-slate-700/50">
                  <div className="w-8 h-8 rounded-full bg-indigo-600 flex-shrink-0 flex items-center justify-center text-xs font-black">2</div>
                  <p className="text-xs text-slate-300">Chọn <b>"Cài đặt"</b>. Ứng dụng sẽ tự động xuất hiện trên <b>Desktop</b> và <b>Taskbar</b>.</p>
                </div>
                <div className="flex gap-4 p-4 bg-slate-800/50 rounded-2xl border border-slate-700/50">
                  <div className="w-8 h-8 rounded-full bg-indigo-600 flex-shrink-0 flex items-center justify-center text-xs font-black">3</div>
                  <p className="text-xs text-slate-300">Bây giờ bạn có thể mở nó bất cứ lúc nào như file <b>.exe</b> thật sự.</p>
                </div>
              </div>

              <button 
                onClick={() => setShowDesktopGuide(false)}
                className="w-full mt-8 py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-2xl transition-all uppercase tracking-widest text-xs"
              >
                ĐÃ HIỂU
              </button>
            </div>
          </div>
        </div>
      )}

      {error && (
        <div className="fixed bottom-6 right-6 bg-red-600 text-white px-6 py-4 rounded-2xl shadow-2xl z-[100] border-2 border-white/20 font-bold flex items-center gap-3">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          {error}
        </div>
      )}
    </div>
  );
};

export default App;

