                    <ColorSelector label="Bg Color" selected={config.line2BgColor} onSelect={(c) => onChange({ line2BgColor: c })} />
                    <div className="grid grid-cols-2 gap-4">
                        <Slider label="Pad X" value={config.line2BgPaddingX} min={0} max={100} onChange={(v) => onChange({ line2BgPaddingX: v })} />
                        <Slider label="Pad Y" value={config.line2BgPaddingY} min={0} max={100} onChange={(v) => onChange({ line2BgPaddingY: v })} />
                    </div>
                  </>
                )}
              </div>

              <div className="bg-slate-900/40 p-3 rounded-lg border border-slate-800/60 space-y-3">
                 <div className="flex items-center justify-between">
                    <SectionHeader title="Drop Shadow / Glow" />
                    <button 
                      onClick={() => onChange({ line2ShowShadow: !config.line2ShowShadow })}
                      className={`px-2 py-0.5 rounded text-[10px] font-black uppercase transition-all ${config.line2ShowShadow ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}
                    >
                      {config.line2ShowShadow ? 'Enabled' : 'Disabled'}
                    </button>
                 </div>
                 {config.line2ShowShadow && (
                   <>
                     <div className="grid grid-cols-2 gap-4">
                       <Slider label="Blur" value={config.line2ShadowBlur} min={0} max={30} onChange={(v) => onChange({ line2ShadowBlur: v })} />
                       <Slider label="Dist" value={config.line2ShadowOffset} min={0} max={20} onChange={(v) => onChange({ line2ShadowOffset: v })} />
                     </div>
                     <ColorSelector label="Shadow Color" selected={config.line2ShadowColor} onSelect={(c) => onChange({ line2ShadowColor: c })} />
                   </>
                 )}
              </div>
            </div>
          </div>
        )}
      </section>
    </div>
  );
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppStatus, SuggestionResponse, ThumbnailConfig } from './types';
import { DEFAULT_CONFIG } from './constants';
import { analyzeScript, generateThumbnailImage } from './services/geminiService';
import { EditorControls } from './components/EditorControls';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [script, setScript] = useState('');
  const [language, setLanguage] = useState('Vietnamese');
  const [suggestions, setSuggestions] = useState<SuggestionResponse | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // History State
  const [history, setHistory] = useState<{
    past: ThumbnailConfig[];
    present: ThumbnailConfig;
    future: ThumbnailConfig[];
  }>({
    past: [],
    present: DEFAULT_CONFIG,
    future: []
  });

  const config = history.present;

  const [error, setError] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [copyStatus, setCopyStatus] = useState<number | null>(null);
  const [previewScale, setPreviewScale] = useState(1);

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textRef = useRef<HTMLDivElement>(null);

  // Sync fullscreen state with browser
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  // Update preview scale factor when window resizes
  useEffect(() => {
    const updateScale = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth;
        setPreviewScale(width / 1280);
      }
    };
    updateScale();
    window.addEventListener('resize', updateScale);
    return () => window.removeEventListener('resize', updateScale);
  }, []);

  // History Actions
  const undo = useCallback(() => {
    setHistory(prev => {
      if (prev.past.length === 0) return prev;
      const previous = prev.past[prev.past.length - 1];
      const newPast = prev.past.slice(0, prev.past.length - 1);
      return {
        past: newPast,
        present: previous,
        future: [prev.present, ...prev.future]
      };
    });
  }, []);

  const redo = useCallback(() => {
    setHistory(prev => {
      if (prev.future.length === 0) return prev;
      const next = prev.future[0];
      const newFuture = prev.future.slice(1);
      return {
        past: [...prev.past, prev.present],
        present: next,
        future: newFuture
      };
    });
  }, []);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'z') {
        if (e.shiftKey) redo();
        else undo();
      } else if ((e.ctrlKey || e.metaKey) && e.key === 'y') {
        redo();
      } else if (e.key === 'F11') {
        e.preventDefault();
        toggleFullscreen();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo]);

  const updateConfig = useCallback((updates: Partial<ThumbnailConfig>, skipHistory = false) => {
    setHistory(prev => {
      const nextPresent = { ...prev.present, ...updates };

      if (skipHistory) {
        return { ...prev, present: nextPresent };
      }

      if (JSON.stringify(prev.present) === JSON.stringify(nextPresent)) {
        return prev;
      }

      const newPast = [...prev.past, prev.present].slice(-50);
      return {
        past: newPast,
        present: nextPresent,
        future: []
      };
    });
  }, []);

  const handleAnalyze = async () => {
    if (!script.trim()) return;
    setStatus(AppStatus.ANALYZING);
    setError(null);
    try {
      const result = await analyzeScript(script, language);
      setSuggestions(result);
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to analyze script. Please try again.');
      setStatus(AppStatus.IDLE);
    }
  };

  const handleGenerateImage = async (prompt: string) => {
    setStatus(AppStatus.GENERATING_IMAGE);
    setError(null);
    try {
      const url = await generateThumbnailImage(prompt);
      updateConfig({ imageUrl: url });
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to generate image. Please try again.');
      setStatus(AppStatus.READY);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateConfig({ imageUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  const applyTitleSuggestion = (title: string) => {
    const words = title.split(' ');
    if (words.length > 3) {
      const middle = Math.ceil(words.length / 2);
      updateConfig({
        line1Text: words.slice(0, middle).join(' ').toUpperCase(),
        line2Text: words.slice(middle).join(' ').toUpperCase(),
        showLine2: true
      });
    } else {
      updateConfig({
        line1Text: title.toUpperCase(),
        showLine2: false
      });
    }
  };

  const handleCopyPrompt = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopyStatus(index);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const updatePrompt = (index: number, newText: string) => {
    if (!suggestions) return;
    const newPrompts = [...suggestions.imagePrompts];
    newPrompts[index] = newText;
    setSuggestions({ ...suggestions, imagePrompts: newPrompts });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!textRef.current || !containerRef.current) return;
    setIsDragging(true);
    const textRect = textRef.current.getBoundingClientRect();
    const offsetX = e.clientX - (textRect.left + textRect.width / 2);
    const offsetY = e.clientY - (textRect.top + textRect.height / 2);
    setDragOffset({ x: offsetX, y: offsetY });
    e.stopPropagation();
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const adjustedX = e.clientX - dragOffset.x;
    const adjustedY = e.clientY - dragOffset.y;
    const x = ((adjustedX - rect.left) / rect.width) * 100;
    const y = ((adjustedY - rect.top) / rect.height) * 100;

    updateConfig({ 
      textPosition: { x: Math.max(0, Math.min(100, x)), y: Math.max(0, Math.min(100, y)) } 
    }, true);
  }, [isDragging, dragOffset, updateConfig]);

  const handleMouseUp = useCallback(() => {
    if (isDragging) {
      setIsDragging(false);
      updateConfig({}); 
    }
  }, [isDragging, updateConfig]);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'grabbing';
    } else {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = '';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, handleMouseMove, handleMouseUp]);

  const downloadThumbnail = () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1280;
    canvas.height = 720;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
        ctx.clearRect(0, 0, 1280, 720);
        ctx.drawImage(img, 0, 0, 1280, 720);
        ctx.fillStyle = `rgba(0, 0, 0, ${config.overlayOpacity / 100})`;
        ctx.fillRect(0, 0, 1280, 720);

        const tx = (config.textPosition.x / 100) * 1280;
        const ty = (config.textPosition.y / 100) * 720;
        ctx.textBaseline = 'middle';
        ctx.lineJoin = 'round';

        const drawLine = (text: string, color: string, color2: string, isGradient: boolean, fontSize: number, strokeWidth: number, strokeColor: string, align: 'left' | 'center' | 'right', bold: boolean, italic: boolean, underline: boolean, showShadow: boolean, shadowBlur: number, shadowOffset: number, shadowColor: string, showBg: boolean, bgColor: string, bgPadX: number, bgPadY: number, y: number) => {
            const fontStyle = italic ? 'italic' : '';
            const fontWeight = bold ? 'bold' : 'normal';
            ctx.save();
            ctx.font = `${fontStyle} ${fontWeight} ${fontSize}px ${config.fontFamily}`; 
            ctx.textAlign = align;

            const textMetrics = ctx.measureText(text.toUpperCase());
            const textWidth = textMetrics.width;

            if (showBg) {
               ctx.fillStyle = bgColor;
               let rx = tx;
               if (align === 'center') rx = tx - textWidth / 2;
               else if (align === 'right') rx = tx - textWidth;
               ctx.fillRect(rx - bgPadX, y - fontSize/2 - bgPadY, textWidth + bgPadX * 2, fontSize + bgPadY * 2);
            }

            if (showShadow) {
              ctx.shadowColor = shadowColor;
              ctx.shadowBlur = shadowBlur;
              ctx.shadowOffsetX = shadowOffset;
              ctx.shadowOffsetY = shadowOffset;
            }

            if (isGradient) {
              const gradient = ctx.createLinearGradient(tx, y - fontSize/2, tx, y + fontSize/2);
              gradient.addColorStop(0, color);
              gradient.addColorStop(1, color2);
              ctx.fillStyle = gradient;
            } else {
              ctx.fillStyle = color;
            }

            if (strokeWidth > 0) {
              ctx.lineWidth = strokeWidth * 2; 
              ctx.strokeStyle = strokeColor;
              ctx.strokeText(text.toUpperCase(), tx, y);
            }

            ctx.fillText(text.toUpperCase(), tx, y);

            if (underline) {
              let lineXStart = tx;
              if (align === 'center') lineXStart = tx - textWidth / 2;
              else if (align === 'right') lineXStart = tx - textWidth;
              const lineY = y + fontSize * 0.45;
              ctx.beginPath();
              ctx.moveTo(lineXStart, lineY);
              ctx.lineTo(lineXStart + textWidth, lineY);
              ctx.lineWidth = fontSize * 0.08;
              ctx.strokeStyle = color;
              ctx.stroke();
            }
            ctx.restore();
        };

        if (config.showLine2) {
            drawLine(config.line1Text, config.line1Color, config.line1Color2, config.line1IsGradient, config.line1FontSize, config.line1StrokeWidth, config.line1StrokeColor, config.line1Align, config.line1Bold, config.line1Italic, config.line1Underline, config.line1ShowShadow, config.line1ShadowBlur, config.line1ShadowOffset, config.line1ShadowColor, config.line1ShowBg, config.line1BgColor, config.line1BgPaddingX, config.line1BgPaddingY, ty - (config.line1FontSize / 2) - config.line1BgPaddingY/2);
            drawLine(config.line2Text, config.line2Color, config.line2Color2, config.line2IsGradient, config.line2FontSize, config.line2StrokeWidth, config.line2StrokeColor, config.line2Align, config.line2Bold, config.line2Italic, config.line2Underline, config.line2ShowShadow, config.line2ShadowBlur, config.line2ShadowOffset, config.line2ShadowColor, config.line2ShowBg, config.line2BgColor, config.line2BgPaddingX, config.line2BgPaddingY, ty + (config.line2FontSize / 2) + config.line2BgPaddingY/2);
        } else {
            drawLine(config.line1Text, config.line1Color, config.line1Color2, config.line1IsGradient, config.line1FontSize, config.line1StrokeWidth, config.line1StrokeColor, config.line1Align, config.line1Bold, config.line1Italic, config.line1Underline, config.line1ShowShadow, config.line1ShadowBlur, config.line1ShadowOffset, config.line1ShadowColor, config.line1ShowBg, config.line1BgColor, config.line1BgPaddingX, config.line1BgPaddingY, ty);
        }

      const link = document.createElement('a');
      link.download = `thumbnail-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    };
    img.src = config.imageUrl || 'https://picsum.photos/1280/720?grayscale';
  };

  const getTextStyle = (line: 'line1' | 'line2') => {
    const isLine1 = line === 'line1';
    const c = config;
    const txtColor = isLine1 ? c.line1Color : c.line2Color;
    const txtColor2 = isLine1 ? c.line1Color2 : c.line2Color2;
    const isGrad = isLine1 ? c.line1IsGradient : c.line2IsGradient;
    const sShow = isLine1 ? c.line1ShowShadow : c.line2ShowShadow;
    const sColor = isLine1 ? c.line1ShadowColor : c.line2ShadowColor;
    const sBlur = isLine1 ? c.line1ShadowBlur : c.line2ShowBlur;
    const sOffset = isLine1 ? c.line1ShadowOffset : c.line2ShadowOffset;
    const strokeW = isLine1 ? c.line1StrokeWidth : c.line2StrokeWidth;
    const strokeC = isLine1 ? c.line1StrokeColor : c.line2StrokeColor;
    const align = isLine1 ? c.line1Align : c.line2Align;
    const fSize = isLine1 ? c.line1FontSize : c.line2FontSize;
    const bold = isLine1 ? c.line1Bold : c.line2Bold;
    const italic = isLine1 ? c.line1Italic : c.line2Italic;
    const underline = isLine1 ? c.line1Underline : c.line2Underline;
    const showBg = isLine1 ? c.line1ShowBg : c.line2ShowBg;
    const bgColor = isLine1 ? c.line1BgColor : c.line2BgColor;
    const bgPadX = isLine1 ? c.line1BgPaddingX : c.line2BgPaddingX;
    const bgPadY = isLine1 ? c.line1BgPaddingY : c.line2BgPaddingY;

    return {
      fontSize: `${fSize * previewScale}px`,
      WebkitTextStroke: `${strokeW * previewScale}px ${strokeC}`,
      textAlign: align as any,
      fontWeight: bold ? 'bold' : 'normal',
      fontStyle: italic ? 'italic' : 'normal',
      textDecoration: underline ? 'underline' : 'none',
      width: '100%',
      display: 'inline-block',
      lineHeight: '1.2',
      ...(showBg ? {
        backgroundColor: bgColor,
        padding: `${bgPadY * previewScale}px ${bgPadX * previewScale}px`,
      } : {}),
      ...(isGrad ? {
        backgroundImage: `linear-gradient(to bottom, ${txtColor}, ${txtColor2})`,
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
      } : {
        color: txtColor,
      }),
      ...(sShow ? {
        filter: `drop-shadow(${sOffset * previewScale}px ${sOffset * previewScale}px ${sBlur * previewScale}px ${sColor})`
      } : {})
    };
  };

  return (
    <div className="flex flex-col h-[100dvh] max-h-[100dvh] overflow-hidden bg-slate-950 text-slate-100">
      <header className="h-16 flex items-center justify-between px-6 border-b border-slate-800 bg-slate-900/80 backdrop-blur-md z-50">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
          </div>
          <span className="font-black tracking-tighter text-2xl bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">THUMBNAIL.AI</span>
          <span className="hidden sm:inline-block px-2.5 py-0.5 rounded text-[12px] bg-slate-800 text-slate-400 font-bold border border-slate-700">STUDIO PRO</span>
        </div>

        <div className="flex items-center gap-5">
          <button 
            onClick={toggleFullscreen}
            className="p-2 rounded-md text-slate-400 hover:bg-slate-800 hover:text-white transition-all"
            title={isFullscreen ? "Thoát toàn màn hình" : "Toàn màn hình (F11)"}
          >
            {isFullscreen ? (
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 9L4 4m0 0l4 4m-4-4v4m0-4h4m10 10l5 5m0 0l-5-5m5 5v-4m0 4h-4M15 9l5-5m0 0l-5 5m5-5v4m0-4h-4M9 15l-5 5m0 0l5-5m-5 5v-4m0 4h4" /></svg>
            ) : (
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5v-4m0 4h-4m4 0l-5-5" /></svg>
            )}
          </button>

          <div className="flex items-center gap-1.5 bg-slate-800/50 p-1.5 rounded-lg border border-slate-700/50">
            <button 
              onClick={undo}
              disabled={history.past.length === 0}
              className={`p-1.5 rounded-md transition-all ${history.past.length === 0 ? 'text-slate-600' : 'text-slate-200 hover:bg-slate-700 hover:text-white'}`}
              title="Undo (Ctrl+Z)"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
            </button>
            <button 
              onClick={redo}
              disabled={history.future.length === 0}
              className={`p-1.5 rounded-md transition-all ${history.future.length === 0 ? 'text-slate-600' : 'text-slate-200 hover:bg-slate-700 hover:text-white'}`}
              title="Redo (Ctrl+Y)"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 10h-10a8 8 0 00-8 8v2m18-10l-6 6m6-6l-6-6" /></svg>
            </button>
          </div>

          <button onClick={() => updateConfig(DEFAULT_CONFIG)} className="text-sm font-bold text-slate-400 hover:text-white transition-colors">RESET</button>

          <button 
            onClick={downloadThumbnail} 
            className="flex items-center gap-2.5 px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white text-sm font-black rounded-full transition-all shadow-lg shadow-indigo-500/20 active:scale-95"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
            XUẤT ẢNH
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-[320px] border-r border-slate-800 bg-slate-900/40 flex flex-col overflow-hidden">
          <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-5">
            <div className="flex items-center gap-2.5 mb-2.5">
              <span className="w-6 h-6 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-[12px] font-bold text-slate-400">2</span>
              <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Design Editor</h3>
            </div>
            <EditorControls config={config} onChange={updateConfig} />
          </div>
        </aside>

        <section className="flex-1 bg-slate-950 workspace-bg flex flex-col items-center p-8 relative overflow-y-auto custom-scrollbar">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[900px] h-[900px] bg-indigo-500/[0.03] blur-[160px] rounded-full pointer-events-none" />

          <div className="w-full max-w-[1100px] space-y-10 z-10">

            <div className="bg-slate-900/60 border border-slate-800 rounded-3xl p-8 shadow-2xl backdrop-blur-md">
              <div className="flex items-center justify-between mb-5">
                <div className="flex items-center gap-4">
                  <span className="w-7 h-7 rounded-full bg-indigo-600 flex items-center justify-center text-[13px] font-black text-white shadow-lg shadow-indigo-500/30">1</span>
                  <h3 className="text-sm font-black text-slate-300 uppercase tracking-widest">Concept Ideation</h3>
                </div>
                <div className="flex gap-2.5">
                  {['Vietnamese', 'English'].map((lang) => (
                    <button
                      key={lang}
                      onClick={() => setLanguage(lang)}
                      className={`px-4 py-2 rounded-lg text-[12px] font-bold transition-all border ${language === lang ? 'bg-indigo-600/10 border-indigo-500 text-indigo-400' : 'bg-slate-800/50 border-slate-700 text-slate-500'}`}
                    >
                      {lang === 'Vietnamese' ? 'Tiếng Việt' : 'English'}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex flex-col md:flex-row gap-5">
                <div className="flex-1">
                  <textarea
                    placeholder="Dán kịch bản hoặc mô tả nội dung video của bạn vào đây..."
                    className="w-full h-32 bg-slate-950/50 border border-slate-800 rounded-2xl p-5 text-base focus:ring-1 focus:ring-indigo-500 outline-none transition-all resize-none placeholder:text-slate-700"
                    value={script}
                    onChange={(e) => setScript(e.target.value)}
                  />
                </div>
                <div className="flex flex-col gap-4 min-w-[240px]">
                  <button
                    onClick={handleAnalyze}
                    disabled={status === AppStatus.ANALYZING || !script}
                    className="flex-1 py-4 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 font-black rounded-2xl transition-all shadow-xl shadow-indigo-500/10 text-sm tracking-tight flex items-center justify-center gap-2"
                  >
                    {status === AppStatus.ANALYZING ? (
                      <>
                        <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
