                {!config.imageUrl && (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 opacity-50 pointer-events-none">
                    <svg className="w-20 h-20 mb-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <p className="text-[14px] font-black tracking-[0.35em] uppercase">Sẵn sàng thiết kế</p>
                  </div>
                )}

                <div className="absolute inset-0 bg-black pointer-events-none" style={{ opacity: config.overlayOpacity / 100 }} />

                <div 
                  ref={textRef}
                  onMouseDown={handleMouseDown}
                  className={`absolute flex flex-col leading-[1.0] uppercase pointer-events-auto transition-all cursor-grab active:cursor-grabbing group p-6 rounded-lg border-2 border-transparent hover:border-indigo-500/30 hover:bg-white/5 ${isDragging ? 'scale-105 z-50 !border-indigo-500/50 bg-white/10' : ''}`}
                  style={{ 
                    left: `${config.textPosition.x}%`,
                    top: `${config.textPosition.y}%`, 
                    transform: 'translate(-50%, -50%)',
                    fontFamily: config.fontFamily,
                    textAlign: 'center'
                  }}
                >
                  <span className="block whitespace-nowrap" style={getTextStyle('line1')}>{config.line1Text}</span>
                  {config.showLine2 && <span className="block whitespace-nowrap" style={getTextStyle('line2')}>{config.line2Text}</span>}
                </div>

                {status === AppStatus.GENERATING_IMAGE && (
                  <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center text-center p-10 z-[60]">
