              </div>
            </div>

            <div className="relative group">
              <div 
                ref={containerRef}
                className={`canvas-container w-full select-none border border-slate-800/60 overflow-hidden shadow-indigo-500/5 ${config.imageUrl ? '' : 'bg-slate-900'}`}
