              >
                {!config.imageUrl && (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 opacity-50 pointer-events-none">
                    <svg className="w-18 h-18 mb-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <p className="text-[13px] font-black tracking-[0.35em] uppercase">Sẵn sàng thiết kế</p>
                  </div>
                )}

                <div className="absolute inset-0 bg-black pointer-events-none" style={{ opacity: config.overlayOpacity / 100 }} />

                <div 
                  ref={textRef}
                  onMouseDown={handleMouseDown}
                  className={`absolute flex flex-col leading-[1.0] uppercase pointer-events-auto transition-all cursor-grab active:cursor-grabbing group p-5 rounded-lg border-2 border-transparent hover:border-indigo-500/30 hover:bg-white/5 ${isDragging ? 'scale-105 z-50 !border-indigo-500/50 bg-white/10' : ''}`}
                  style={{ 
                    left: `${config.textPosition.x}%`,
                    top: `${config.textPosition.y}%`, 
                    transform: 'translate(-50%, -50%)',
                    fontFamily: config.fontFamily,
                    textAlign: 'center'
                  }}
                >
                  <span className="block whitespace-nowrap" style={getTextStyle('line1')}>{config.line1Text}</span>
                  {config.showLine2 && <span className="block whitespace-nowrap" style={getTextStyle('line2')}>{config.line2Text}</span>}
                </div>

                {status === AppStatus.GENERATING_IMAGE && (
                  <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center text-center p-10 z-[60]">
                    <div className="w-18 h-18 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin mb-5"></div>
                    <p className="text-white font-black tracking-[0.2em] text-[12px] uppercase animate-pulse">ĐANG VẼ ẢNH BẰNG AI...</p>
                  </div>
                )}
              </div>

              <div className="mt-5 flex flex-col gap-5 bg-slate-900/60 p-6 rounded-3xl border border-slate-800 shadow-xl">
                <div className="flex justify-between items-center">
                  <div className="flex items-center gap-8">
                    <span className="text-[11px] font-black text-slate-300 uppercase tracking-widest">VỊ TRÍ TIÊU ĐỀ</span>
                  </div>
                  <button onClick={() => updateConfig({ textPosition: { x: 50, y: 50 } })} className="px-6 py-2.5 bg-indigo-600/10 hover:bg-indigo-600 text-[11px] font-black text-indigo-400 hover:text-white rounded-xl transition-all border border-indigo-500/30 active:scale-95 uppercase">CĂN GIỮA</button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-10 pt-3 border-t border-slate-800/50">
                  <div className="space-y-4">
                    <div className="flex justify-between items-center">
                      <label className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Ngang (X)</label>
                      <span className="text-[16px] text-indigo-400 font-mono font-bold">{Math.round(config.textPosition.x)}%</span>
                    </div>
                    <input type="range" min="0" max="100" value={config.textPosition.x} onChange={(e) => updateConfig({ textPosition: { ...config.textPosition, x: parseFloat(e.target.value) } }, true)} onMouseUp={() => updateConfig({})} className="w-full h-2 bg-slate-800 rounded-full appearance-none accent-indigo-500 cursor-pointer" />
                  </div>

                  <div className="space-y-4">
                    <div className="flex justify-between items-center">
                      <label className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Dọc (Y)</label>
                      <span className="text-[16px] text-indigo-400 font-mono font-bold">{Math.round(config.textPosition.y)}%</span>
                    </div>
                    <input type="range" min="0" max="100" value={config.textPosition.y} onChange={(e) => updateConfig({ textPosition: { ...config.textPosition, y: parseFloat(e.target.value) } }, true)} onMouseUp={() => updateConfig({})} className="w-full h-2 bg-slate-800 rounded-full appearance-none accent-indigo-500 cursor-pointer" />
                  </div>
                </div>
              </div>
            </div>
          </div>
        </section>

        <aside className="w-[330px] border-l border-slate-800 bg-slate-900/60 flex flex-col overflow-hidden">
          <div className="p-6 border-b border-slate-800 bg-slate-900/40">
            <h3 className="text-sm font-black text-indigo-400 uppercase tracking-widest">Gợi ý từ AI</h3>
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
            {suggestions ? (
              <div className="space-y-10">
                <div>
                  <h4 className="text-[11px] font-black text-slate-500 uppercase mb-5 tracking-wider">Tiêu đề thu hút</h4>
                  <div className="grid gap-3">
                    {suggestions.titles.map((title, i) => (
                      <button key={i} onClick={() => applyTitleSuggestion(title)} className="w-full text-left p-4 rounded-xl bg-slate-950/50 border border-slate-800 hover:border-indigo-500 hover:bg-indigo-500/5 transition-all group">
                        <span className="block text-[12px] font-black uppercase text-slate-300 group-hover:text-white">{title}</span>
                      </button>
                    ))}
                  </div>
                </div>
                <div>
                  <h4 className="text-[11px] font-black text-slate-500 uppercase mb-5 tracking-wider">Bối cảnh hình ảnh</h4>
                  <div className="space-y-5">
                    {suggestions.imagePrompts.map((p, i) => (
                      <div key={i} className="flex flex-col gap-3 p-4 rounded-xl bg-slate-950/50 border border-slate-800">
                        <textarea value={p} onChange={(e) => updatePrompt(i, e.target.value)} className="w-full bg-transparent text-[11px] text-slate-400 rendering-relaxed min-h-[80px] outline-none resize-none border-none p-0" />
                        <div className="flex gap-3 pt-3 border-t border-slate-900">
                          <button onClick={() => handleCopyPrompt(p, i)} className="flex-1 py-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-[10px] font-bold text-slate-400">{copyStatus === i ? 'ĐÃ COPY' : 'COPY MÔ TẢ'}</button>
                          <button onClick={() => handleGenerateImage(p)} disabled={status === AppStatus.GENERATING_IMAGE} className="flex-[2] py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-[10px] font-black text-white">{status === AppStatus.GENERATING_IMAGE ? 'ĐANG VẼ...' : 'VẼ BACKGROUND'}</button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-center px-6">
                <p className="text-[11px] font-bold text-slate-500 uppercase tracking-[0.25em]">Hãy nhập nội dung ở Bước 1</p>
              </div>
            )}
          </div>
        </aside>
      </main>

      {error && (
        <div className="fixed bottom-7 right-7 bg-red-600 text-white px-7 py-5 rounded-2xl shadow-2xl z-[100] border-2 border-white/20 font-bold flex items-center gap-4 text-base">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          {error}
        </div>
      )}
    </div>
  );
};

export default App;

export interface SuggestionResponse {
  titles: string[];
  imagePrompts: string[];
}

export interface GraphicElement {
  id: string;
  type: 'icon' | 'shape';
  path: string;
  x: number;
  y: number;
  size: number;
  color: string;
  rotation: number;
}

export interface ThumbnailConfig {
  imageUrl: string | null;
  fontFamily: string;
  textPosition: { x: number; y: number };
  overlayOpacity: number;
  graphics: GraphicElement[];

  // Line 1 Styling
  line1Text: string;
