import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppStatus, SuggestionResponse, ThumbnailConfig } from './types';
import { DEFAULT_CONFIG } from './constants';
import { analyzeScript, generateThumbnailImage } from './services/geminiService';
import { EditorControls } from './components/EditorControls';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [script, setScript] = useState('');
  const [language, setLanguage] = useState('Vietnamese');
  const [suggestions, setSuggestions] = useState<SuggestionResponse | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // History State
  const [history, setHistory] = useState<{
    past: ThumbnailConfig[];
    present: ThumbnailConfig;
    future: ThumbnailConfig[];
  }>({
    past: [],
    present: DEFAULT_CONFIG,
    future: []
  });

  const config = history.present;

  const [error, setError] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [copyStatus, setCopyStatus] = useState<number | null>(null);
  const [previewScale, setPreviewScale] = useState(1);

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textRef = useRef<HTMLDivElement>(null);

  // Sync fullscreen state with browser
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  // Update preview scale factor when window resizes
  useEffect(() => {
    const updateScale = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth;
        setPreviewScale(width / 1280);
      }
    };
    updateScale();
    window.addEventListener('resize', updateScale);
    return () => window.removeEventListener('resize', updateScale);
  }, []);

  // History Actions
  const undo = useCallback(() => {
    setHistory(prev => {
      if (prev.past.length === 0) return prev;
      const previous = prev.past[prev.past.length - 1];
      const newPast = prev.past.slice(0, prev.past.length - 1);
      return {
        past: newPast,
        present: previous,
        future: [prev.present, ...prev.future]
      };
    });
  }, []);

  const redo = useCallback(() => {
    setHistory(prev => {
      if (prev.future.length === 0) return prev;
      const next = prev.future[0];
      const newFuture = prev.future.slice(1);
      return {
        past: [...prev.past, prev.present],
        present: next,
        future: newFuture
      };
    });
  }, []);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'z') {
        if (e.shiftKey) redo();
        else undo();
      } else if ((e.ctrlKey || e.metaKey) && e.key === 'y') {
        redo();
      } else if (e.key === 'F11') {
        e.preventDefault();
        toggleFullscreen();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo]);

  const updateConfig = useCallback((updates: Partial<ThumbnailConfig>, skipHistory = false) => {
    setHistory(prev => {
      const nextPresent = { ...prev.present, ...updates };

      if (skipHistory) {
        return { ...prev, present: nextPresent };
      }

      if (JSON.stringify(prev.present) === JSON.stringify(nextPresent)) {
        return prev;
      }

      const newPast = [...prev.past, prev.present].slice(-50);
      return {
        past: newPast,
        present: nextPresent,
        future: []
      };
    });
  }, []);

  const handleAnalyze = async () => {
    if (!script.trim()) return;
    setStatus(AppStatus.ANALYZING);
    setError(null);
    try {
      const result = await analyzeScript(script, language);
      setSuggestions(result);
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to analyze script. Please try again.');
      setStatus(AppStatus.IDLE);
    }
  };

  const handleGenerateImage = async (prompt: string) => {
    setStatus(AppStatus.GENERATING_IMAGE);
    setError(null);
    try {
      const url = await generateThumbnailImage(prompt);
      updateConfig({ imageUrl: url });
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to generate image. Please try again.');
      setStatus(AppStatus.READY);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateConfig({ imageUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  const applyTitleSuggestion = (title: string) => {
    const words = title.split(' ');
    if (words.length > 6) {
      // Split into 3 lines
      const segment = Math.ceil(words.length / 3);
      updateConfig({
        line1Text: words.slice(0, segment).join(' ').toUpperCase(),
        line2Text: words.slice(segment, segment * 2).join(' ').toUpperCase(),
        line3Text: words.slice(segment * 2).join(' ').toUpperCase(),
        showLine2: true,
        showLine3: true
      });
    } else if (words.length > 3) {
      // Split into 2 lines
      const middle = Math.ceil(words.length / 2);
      updateConfig({
        line1Text: words.slice(0, middle).join(' ').toUpperCase(),
        line2Text: words.slice(middle).join(' ').toUpperCase(),
        showLine2: true,
        showLine3: false
      });
    } else {
      updateConfig({
        line1Text: title.toUpperCase(),
        showLine2: false,
        showLine3: false
      });
    }
  };

  const handleCopyPrompt = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopyStatus(index);
    setTimeout(() => setCopyStatus(null), 2000);
  };

