    if (!textRef.current || !containerRef.current) return;
    setIsDragging(true);
    const textRect = textRef.current.getBoundingClientRect();
    const offsetX = e.clientX - (textRect.left + textRect.width / 2);
    const offsetY = e.clientY - (textRect.top + textRect.height / 2);
    setDragOffset({ x: offsetX, y: offsetY });
    e.stopPropagation();
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const adjustedX = e.clientX - dragOffset.x;
    const adjustedY = e.clientY - dragOffset.y;
    const x = ((adjustedX - rect.left) / rect.width) * 100;
    const y = ((adjustedY - rect.top) / rect.height) * 100;

    updateConfig({ 
      textPosition: { x: Math.max(0, Math.min(100, x)), y: Math.max(0, Math.min(100, y)) } 
    }, true);
  }, [isDragging, dragOffset, updateConfig]);

  const handleMouseUp = useCallback(() => {
    if (isDragging) {
      setIsDragging(false);
      updateConfig({}); 
    }
  }, [isDragging, updateConfig]);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'grabbing';
    } else {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = '';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, handleMouseMove, handleMouseUp]);

  const downloadThumbnail = () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1280;
    canvas.height = 720;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
        ctx.clearRect(0, 0, 1280, 720);
        ctx.drawImage(img, 0, 0, 1280, 720);
        ctx.fillStyle = `rgba(0, 0, 0, ${config.overlayOpacity / 100})`;
        ctx.fillRect(0, 0, 1280, 720);

        const tx = (config.textPosition.x / 100) * 1280;
        const ty = (config.textPosition.y / 100) * 720;
        ctx.textBaseline = 'middle';
        ctx.lineJoin = 'round';

        const drawLine = (text: string, color: string, color2: string, isGradient: boolean, fontSize: number, strokeWidth: number, strokeColor: string, align: 'left' | 'center' | 'right', bold: boolean, italic: boolean, underline: boolean, showShadow: boolean, shadowBlur: number, shadowOffset: number, shadowColor: string, showBg: boolean, bgColor: string, bgPadX: number, bgPadY: number, y: number) => {
            const fontStyle = italic ? 'italic' : '';
            const fontWeight = bold ? 'bold' : 'normal';
            ctx.save();
            ctx.font = `${fontStyle} ${fontWeight} ${fontSize}px ${config.fontFamily}`; 
            ctx.textAlign = align;

            const textMetrics = ctx.measureText(text.toUpperCase());
            const textWidth = textMetrics.width;

            if (showBg) {
               ctx.fillStyle = bgColor;
               let rx = tx;
               if (align === 'center') rx = tx - textWidth / 2;
               else if (align === 'right') rx = tx - textWidth;
               ctx.fillRect(rx - bgPadX, y - fontSize/2 - bgPadY, textWidth + bgPadX * 2, fontSize + bgPadY * 2);
            }

            if (showShadow) {
              ctx.shadowColor = shadowColor;
              ctx.shadowBlur = shadowBlur;
              ctx.shadowOffsetX = shadowOffset;
              ctx.shadowOffsetY = shadowOffset;
            }

            if (isGradient) {
              const gradient = ctx.createLinearGradient(tx, y - fontSize/2, tx, y + fontSize/2);
              gradient.addColorStop(0, color);
              gradient.addColorStop(1, color2);
              ctx.fillStyle = gradient;
            } else {
              ctx.fillStyle = color;
            }

            if (strokeWidth > 0) {
              ctx.lineWidth = strokeWidth * 2; 
              ctx.strokeStyle = strokeColor;
              ctx.strokeText(text.toUpperCase(), tx, y);
            }

            ctx.fillText(text.toUpperCase(), tx, y);

            if (underline) {
              let lineXStart = tx;
              if (align === 'center') lineXStart = tx - textWidth / 2;
              else if (align === 'right') lineXStart = tx - textWidth;
              const lineY = y + fontSize * 0.45;
              ctx.beginPath();
              ctx.moveTo(lineXStart, lineY);
              ctx.lineTo(lineXStart + textWidth, lineY);
              ctx.lineWidth = fontSize * 0.08;
              ctx.strokeStyle = color;
              ctx.stroke();
