        >
          {align === 'left' && <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h10M4 18h16" /></svg>}
          {align === 'center' && <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M7 12h10M4 18h16" /></svg>}
          {align === 'right' && <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M10 12h10M4 18h16" /></svg>}
        </button>
      ))}
    </div>
  );

  const FontStyleControl = ({ bold, italic, underline, onBold, onItalic, onUnderline }: { bold: boolean, italic: boolean, underline: boolean, onBold: () => void, onItalic: () => void, onUnderline: () => void }) => (
    <div className="flex bg-slate-900 p-1 rounded-lg gap-1 border border-slate-700">
      <button
        onClick={onBold}
        className={`flex-1 flex items-center justify-center p-1 rounded transition-all font-black text-base ${bold ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
      >
        B
      </button>
      <button
        onClick={onItalic}
        className={`flex-1 flex items-center justify-center p-1 rounded transition-all font-serif italic text-base ${italic ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
      >
        I
      </button>
      <button
        onClick={onUnderline}
        className={`flex-1 flex items-center justify-center p-1 rounded transition-all underline font-bold text-base ${underline ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
      >
        U
      </button>
    </div>
  );

  const ColorSelector = ({ selected, onSelect, label }: { selected: string, onSelect: (color: string) => void, label: string }) => (
    <div className="space-y-2">
      <label className="text-[9px] text-slate-500 font-bold uppercase tracking-wider block">{label}</label>
      <div className="flex flex-wrap gap-1.5 mb-1.5">
        {COLOR_PALETTES.map((p) => (
          <button
            key={p.name}
            onClick={() => onSelect(p.color)}
            className={`w-5 h-5 rounded-sm border transition-all ${selected.toLowerCase() === p.color.toLowerCase() ? 'ring-1 ring-indigo-500 ring-offset-1 ring-offset-slate-900 border-white' : 'border-slate-800 hover:border-slate-600'}`}
            style={{ backgroundColor: p.color }}
            title={p.name}
          />
        ))}
      </div>
      <div className="flex items-center gap-2">
        <div className="relative w-7 h-7 shrink-0">
          <input 
            type="color" 
            value={selected.startsWith('#') && selected.length === 7 ? selected : '#ffffff'}
            onChange={(e) => onSelect(e.target.value)}
            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
          />
          <div 
            className="w-full h-full rounded border border-slate-700 shadow-inner"
            style={{ backgroundColor: selected }}
          />
        </div>
        <div className="flex-1">
          <input 
            type="text" 
            value={selected}
            onChange={(e) => onSelect(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-1 text-[11px] font-mono font-bold text-indigo-400 outline-none focus:border-indigo-500 transition-all uppercase"
            placeholder="#HEX"
          />
        </div>
      </div>
    </div>
  );

  const Slider = ({ label, value, min, max, step = 1, onChange, unit = '', showInput = false }: { label: string, value: number, min: number, max: number, step?: number, onChange: (val: number) => void, unit?: string, showInput?: boolean }) => (
    <div className="space-y-1.5">
      <div className="flex justify-between items-center">
        <label className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{label}</label>
        {showInput ? (
          <div className="flex items-center gap-1">
            <input 
              type="number"
              value={value}
              min={min}
              max={max}
              onChange={(e) => {
                const val = parseFloat(e.target.value);
                if (!isNaN(val)) onChange(val);
              }}
              className="w-14 bg-slate-900 border border-slate-700 rounded text-center text-[14px] font-mono font-bold text-indigo-400 outline-none focus:border-indigo-500 p-0.5"
            />
            <span className="text-[11px] text-slate-500 font-bold">{unit}</span>
          </div>
        ) : (
          <ValueDisplay value={value} unit={unit} />
        )}
      </div>
      <input
        type="range" min={min} max={max} step={step} value={value}
        onChange={(e) => onChange(parseFloat(e.target.value))}
        className="w-full h-1 bg-slate-800 rounded appearance-none accent-indigo-500 cursor-pointer"
      />
    </div>
  );

  // Helper to render line controls
  const renderLineControls = (prefix: 'line1' | 'line2' | 'line3', label: string) => {
    const textKey = `${prefix}Text` as keyof ThumbnailConfig;
    const alignKey = `${prefix}Align` as keyof ThumbnailConfig;
    const boldKey = `${prefix}Bold` as keyof ThumbnailConfig;
    const italicKey = `${prefix}Italic` as keyof ThumbnailConfig;
    const underlineKey = `${prefix}Underline` as keyof ThumbnailConfig;
    const gradKey = `${prefix}IsGradient` as keyof ThumbnailConfig;
    const colorKey = `${prefix}Color` as keyof ThumbnailConfig;
    const color2Key = `${prefix}Color2` as keyof ThumbnailConfig;
    const strokeCKey = `${prefix}StrokeColor` as keyof ThumbnailConfig;
    const sizeKey = `${prefix}FontSize` as keyof ThumbnailConfig;
    const strokeWKey = `${prefix}StrokeWidth` as keyof ThumbnailConfig;
    const showBgKey = `${prefix}ShowBg` as keyof ThumbnailConfig;
    const bgColorKey = `${prefix}BgColor` as keyof ThumbnailConfig;
    const bgPadXKey = `${prefix}BgPaddingX` as keyof ThumbnailConfig;
    const bgPadYKey = `${prefix}BgPaddingY` as keyof ThumbnailConfig;
    const showShadowKey = `${prefix}ShowShadow` as keyof ThumbnailConfig;
    const shadowBlurKey = `${prefix}ShadowBlur` as keyof ThumbnailConfig;
    const shadowOffsetKey = `${prefix}ShadowOffset` as keyof ThumbnailConfig;
    const shadowColorKey = `${prefix}ShadowColor` as keyof ThumbnailConfig;
    const posKey = `${prefix}Position` as keyof ThumbnailConfig;

    const currentPos = config[posKey] as { x: number, y: number };

    return (
      <div className="space-y-4">
        <input
          type="text"
          value={config[textKey] as string}
          onChange={(e) => onChange({ [textKey]: e.target.value })}
          className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2.5 text-white font-bold uppercase text-sm mb-4 outline-none focus:border-indigo-500 transition-all placeholder:text-slate-600"
          placeholder={`${label}...`}
        />

        <div className="flex flex-col gap-4">
          {/* Position Controls */}
          <div className="bg-slate-900/40 p-3 rounded-lg border border-slate-800/60 space-y-3">
            <SectionHeader title="Position" />
            <div className="grid grid-cols-2 gap-4">
              <Slider label="X" value={currentPos.x} min={0} max={100} onChange={(v) => onChange({ [posKey]: { ...currentPos, x: v } })} unit="%" />
              <Slider label="Y" value={currentPos.y} min={0} max={100} onChange={(v) => onChange({ [posKey]: { ...currentPos, y: v } })} unit="%" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-[10px] text-slate-400 font-bold uppercase mb-1.5 block tracking-wider">Align</label>
              <AlignmentControl value={config[alignKey] as string} onSelect={(val) => onChange({ [alignKey]: val })} />
            </div>
            <div>
              <label className="text-[10px] text-slate-400 font-bold uppercase mb-1.5 block tracking-wider">Style</label>
              <FontStyleControl 
                bold={config[boldKey] as boolean}
                italic={config[italicKey] as boolean} 
                underline={config[underlineKey] as boolean} 
                onBold={() => onChange({ [boldKey]: !config[boldKey] })}
                onItalic={() => onChange({ [italicKey]: !config[italicKey] })}
                onUnderline={() => onChange({ [underlineKey]: !config[underlineKey] })}
              />
            </div>
          </div>

          <div className="bg-slate-900/40 p-3 rounded-lg border border-slate-800/60">
            <div className="flex items-center justify-between mb-2">
              <label className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Color Gradient</label>
              <button 
                onClick={() => onChange({ [gradKey]: !config[gradKey] })}
                className={`px-2 py-0.5 rounded text-[9px] font-black uppercase transition-all ${config[gradKey] ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}
              >
                {config[gradKey] ? 'On' : 'Off'}
              </button>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <ColorSelector 
                label={config[gradKey] ? "Color Start" : "Text Color"} 
                selected={config[colorKey] as string} 
                onSelect={(color) => onChange({ [colorKey]: color })} 
              />
              {config[gradKey] && (
                <ColorSelector 
                  label="Color End" 
                  selected={config[color2Key] as string} 
                  onSelect={(color) => onChange({ [color2Key]: color })} 
                />
              )}
              <ColorSelector 
                label="Stroke Color" 
                selected={config[strokeCKey] as string} 
                onSelect={(color) => onChange({ [strokeCKey]: color })} 
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <Slider label="Size" value={config[sizeKey] as number} min={20} max={300} onChange={(v) => onChange({ [sizeKey]: v })} showInput={true} unit="px" />
            <Slider label="Stroke" value={config[strokeWKey] as number} min={0} max={10} step={0.5} onChange={(v) => onChange({ [strokeWKey]: v })} />
          </div>

          {/* Background Shape Controls */}
          <div className="bg-slate-900/40 p-3 rounded-lg border border-slate-800/60 space-y-3">
             <div className="flex items-center justify-between">
                <SectionHeader title="Text Background" />
                <button 
                  onClick={() => onChange({ [showBgKey]: !config[showBgKey] })}
                  className={`px-2 py-0.5 rounded text-[9px] font-black uppercase transition-all ${config[showBgKey] ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}
                >
                  {config[showBgKey] ? 'Enabled' : 'Disabled'}
                </button>
             </div>
             {config[showBgKey] && (
               <>
                 <ColorSelector label="Bg Color" selected={config[bgColorKey] as string} onSelect={(c) => onChange({ [bgColorKey]: c })} />
                 <div className="grid grid-cols-2 gap-4">
                    <Slider label="Pad X" value={config[bgPadXKey] as number} min={0} max={100} onChange={(v) => onChange({ [bgPadXKey]: v })} />
                    <Slider label="Pad Y" value={config[bgPadYKey] as number} min={0} max={100} onChange={(v) => onChange({ [bgPadYKey]: v })} />
                 </div>
               </>
             )}
          </div>

          <div className="bg-slate-900/40 p-3 rounded-lg border border-slate-800/60 space-y-3">
             <div className="flex items-center justify-between">
                <SectionHeader title="Drop Shadow / Glow" />
                <button 
                  onClick={() => onChange({ [showShadowKey]: !config[showShadowKey] })}
                  className={`px-2 py-0.5 rounded text-[9px] font-black uppercase transition-all ${config[showShadowKey] ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}
                >
                  {config[showShadowKey] ? 'Enabled' : 'Disabled'}
                </button>
             </div>
             {config[showShadowKey] && (
               <>
                 <div className="grid grid-cols-2 gap-4">
                   <Slider label="Blur" value={config[shadowBlurKey] as number} min={0} max={30} onChange={(v) => onChange({ [shadowBlurKey]: v })} />
                   <Slider label="Dist" value={config[shadowOffsetKey] as number} min={0} max={20} onChange={(v) => onChange({ [shadowOffsetKey]: v })} />
                 </div>
                 <ColorSelector label="Shadow Color" selected={config[shadowColorKey] as string} onSelect={(c) => onChange({ [shadowColorKey]: c })} />
               </>
             )}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col gap-6">

      {/* Typography Section */}
      <section className="bg-slate-950/40 p-4 rounded-xl border border-slate-800/60">
        <SectionHeader title="Global Style" />
        <div className="space-y-4">
          <div>
            <label className="text-[10px] text-slate-400 font-bold uppercase mb-1.5 block tracking-wider">Primary Font</label>
            <select
              value={config.fontFamily}
              onChange={(e) => onChange({ fontFamily: e.target.value })}
              className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2.5 text-white text-xl font-bold outline-none focus:border-indigo-500 transition-all"
            >
              {FONT_FAMILIES.map((f) => (
                <option key={f.name} value={f.value} style={{ fontFamily: f.value }}>{f.name}</option>
              ))}
            </select>
          </div>

          <Slider 
            label="Background Dimming" 
            value={config.overlayOpacity} 
            min={0} max={100} 
            onChange={(v) => onChange({ overlayOpacity: v })} 
            unit="%" 
          />
        </div>
      </section>

      {/* Line 1 Section */}
      <section className="bg-slate-950/40 p-4 rounded-xl border border-slate-800/60">
        <div className="flex justify-between items-center mb-3">
          <SectionHeader title="Line One" />
          <div className="w-2.5 h-2.5 rounded-full bg-indigo-500 animate-pulse" />
        </div>
        {renderLineControls('line1', 'Main Hook')}
      </section>

      {/* Line 2 Section */}
      <section className="bg-slate-950/40 p-4 rounded-xl border border-slate-800/60">
        <div className="flex justify-between items-center mb-3">
          <SectionHeader title="Line Two" />
          <label className="relative inline-flex items-center cursor-pointer">
            <input 
              type="checkbox" 
              checked={config.showLine2} 
              onChange={(e) => onChange({ showLine2: e.target.checked })} 
              className="sr-only peer"
            />
            <div className="w-9 h-5 bg-slate-800 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4.5 after:transition-all peer-checked:bg-indigo-600"></div>
          </label>
        </div>

        {config.showLine2 && renderLineControls('line2', 'Secondary Text')}
      </section>

      {/* Line 3 Section */}
      <section className="bg-slate-950/40 p-4 rounded-xl border border-slate-800/60">
        <div className="flex justify-between items-center mb-3">
          <SectionHeader title="Line Three" />
          <label className="relative inline-flex items-center cursor-pointer">
            <input 
              type="checkbox" 
              checked={config.showLine3} 
              onChange={(e) => onChange({ showLine3: e.target.checked })} 
              className="sr-only peer"
            />
            <div className="w-9 h-5 bg-slate-800 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4.5 after:transition-all peer-checked:bg-indigo-600"></div>
          </label>
        </div>

        {config.showLine3 && renderLineControls('line3', 'Tertiary Text')}
      </section>
    </div>
  );
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppStatus, SuggestionResponse, ThumbnailConfig } from './types';
import { DEFAULT_CONFIG } from './constants';
import { analyzeScript, generateThumbnailImage } from './services/geminiService';
import { EditorControls } from './components/EditorControls';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [script, setScript] = useState('');
  const [language, setLanguage] = useState('Vietnamese');
  const [suggestions, setSuggestions] = useState<SuggestionResponse | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // History State
  const [history, setHistory] = useState<{
    past: ThumbnailConfig[];
    present: ThumbnailConfig;
    future: ThumbnailConfig[];
  }>({
    past: [],
    present: DEFAULT_CONFIG,
    future: []
  });

  const config = history.present;

  const [error, setError] = useState<string | null>(null);
  const [draggingLine, setDraggingLine] = useState<'line1' | 'line2' | 'line3' | null>(null);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [copyStatus, setCopyStatus] = useState<number | null>(null);
  const [previewScale, setPreviewScale] = useState(1);

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const lineRefs = {
    line1: useRef<HTMLDivElement>(null),
    line2: useRef<HTMLDivElement>(null),
    line3: useRef<HTMLDivElement>(null),
  };

  // Sync fullscreen state with browser
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  // Update preview scale factor when window resizes
  useEffect(() => {
    const updateScale = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth;
        setPreviewScale(width / 1280);
      }
    };
    updateScale();
    window.addEventListener('resize', updateScale);
    return () => window.removeEventListener('resize', updateScale);
  }, []);

  // History Actions
  const undo = useCallback(() => {
    setHistory(prev => {
      if (prev.past.length === 0) return prev;
      const previous = prev.past[prev.past.length - 1];
      const newPast = prev.past.slice(0, prev.past.length - 1);
      return {
        past: newPast,
        present: previous,
        future: [prev.present, ...prev.future]
      };
    });
  }, []);

  const redo = useCallback(() => {
    setHistory(prev => {
      if (prev.future.length === 0) return prev;
      const next = prev.future[0];
      const newFuture = prev.future.slice(1);
      return {
        past: [...prev.past, prev.present],
        present: next,
        future: newFuture
      };
    });
  }, []);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'z') {
        if (e.shiftKey) redo();
        else undo();
      } else if ((e.ctrlKey || e.metaKey) && e.key === 'y') {
        redo();
      } else if (e.key === 'F11') {
        e.preventDefault();
        toggleFullscreen();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo]);

  const updateConfig = useCallback((updates: Partial<ThumbnailConfig>, skipHistory = false) => {
    setHistory(prev => {
      const nextPresent = { ...prev.present, ...updates };

      if (skipHistory) {
        return { ...prev, present: nextPresent };
      }

      if (JSON.stringify(prev.present) === JSON.stringify(nextPresent)) {
        return prev;
      }

      const newPast = [...prev.past, prev.present].slice(-50);
      return {
        past: newPast,
        present: nextPresent,
        future: []
      };
    });
  }, []);

  const handleAnalyze = async () => {
    if (!script.trim()) return;
    setStatus(AppStatus.ANALYZING);
    setError(null);
    try {
      const result = await analyzeScript(script, language);
      setSuggestions(result);
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to analyze script. Please try again.');
      setStatus(AppStatus.IDLE);
    }
  };

  const handleGenerateImage = async (prompt: string) => {
    setStatus(AppStatus.GENERATING_IMAGE);
    setError(null);
    try {
      const url = await generateThumbnailImage(prompt);
      updateConfig({ imageUrl: url });
      setStatus(AppStatus.READY);
    } catch (err) {
      setError('Failed to generate image. Please try again.');
      setStatus(AppStatus.READY);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateConfig({ imageUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  const applyTitleSuggestion = (title: string) => {
    const words = title.split(' ');
    if (words.length > 6) {
      const segment = Math.ceil(words.length / 3);
      updateConfig({
        line1Text: words.slice(0, segment).join(' ').toUpperCase(),
        line2Text: words.slice(segment, segment * 2).join(' ').toUpperCase(),
        line3Text: words.slice(segment * 2).join(' ').toUpperCase(),
        showLine2: true,
        showLine3: true
      });
    } else if (words.length > 3) {
      const middle = Math.ceil(words.length / 2);
      updateConfig({
        line1Text: words.slice(0, middle).join(' ').toUpperCase(),
        line2Text: words.slice(middle).join(' ').toUpperCase(),
        showLine2: true,
        showLine3: false
      });
    } else {
      updateConfig({
        line1Text: title.toUpperCase(),
        showLine2: false,
        showLine3: false
      });
    }
  };

  const handleCopyPrompt = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopyStatus(index);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const updatePrompt = (index: number, newText: string) => {
    if (!suggestions) return;
    const newPrompts = [...suggestions.imagePrompts];
    newPrompts[index] = newText;
    setSuggestions({ ...suggestions, imagePrompts: newPrompts });
  };

  const handleMouseDown = (e: React.MouseEvent, line: 'line1' | 'line2' | 'line3') => {
    const ref = lineRefs[line].current;
    if (!ref || !containerRef.current) return;
    setDraggingLine(line);
    const rect = ref.getBoundingClientRect();
    const offsetX = e.clientX - (rect.left + rect.width / 2);
    const offsetY = e.clientY - (rect.top + rect.height / 2);
    setDragOffset({ x: offsetX, y: offsetY });
    e.stopPropagation();
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!draggingLine || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const adjustedX = e.clientX - dragOffset.x;
    const adjustedY = e.clientY - dragOffset.y;
    const x = ((adjustedX - rect.left) / rect.width) * 100;
    const y = ((adjustedY - rect.top) / rect.height) * 100;

    const posKey = `${draggingLine}Position` as keyof ThumbnailConfig;
    updateConfig({ 
      [posKey]: { x: Math.max(0, Math.min(100, x)), y: Math.max(0, Math.min(100, y)) } 
    }, true);
  }, [draggingLine, dragOffset, updateConfig]);

  const handleMouseUp = useCallback(() => {
    if (draggingLine) {
      setDraggingLine(null);
      updateConfig({}); 
    }
  }, [draggingLine, updateConfig]);

  useEffect(() => {
    if (draggingLine) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'grabbing';
    } else {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = '';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [draggingLine, handleMouseMove, handleMouseUp]);

  const downloadThumbnail = () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1280;
    canvas.height = 720;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
        ctx.clearRect(0, 0, 1280, 720);
        ctx.drawImage(img, 0, 0, 1280, 720);
        ctx.fillStyle = `rgba(0, 0, 0, ${config.overlayOpacity / 100})`;
        ctx.fillRect(0, 0, 1280, 720);

        ctx.textBaseline = 'middle';
        ctx.lineJoin = 'round';

        const drawLine = (text: string, color: string, color2: string, isGradient: boolean, fontSize: number, strokeWidth: number, strokeColor: string, align: 'left' | 'center' | 'right', bold: boolean, italic: boolean, underline: boolean, showShadow: boolean, shadowBlur: number, shadowOffset: number, shadowColor: string, showBg: boolean, bgColor: string, bgPadX: number, bgPadY: number, pos: {x: number, y: number}) => {
            const fontStyle = italic ? 'italic' : '';
            const fontWeight = bold ? 'bold' : 'normal';
            const tx = (pos.x / 100) * 1280;
            const ty = (pos.y / 100) * 720;

            ctx.save();
            ctx.font = `${fontStyle} ${fontWeight} ${fontSize}px ${config.fontFamily}`; 
            ctx.textAlign = align;

            const textMetrics = ctx.measureText(text.toUpperCase());
            const textWidth = textMetrics.width;

            if (showBg) {
               ctx.fillStyle = bgColor;
               let rx = tx;
               if (align === 'center') rx = tx - textWidth / 2;
               else if (align === 'right') rx = tx - textWidth;
               ctx.fillRect(rx - bgPadX, ty - fontSize/2 - bgPadY, textWidth + bgPadX * 2, fontSize + bgPadY * 2);
            }

            if (showShadow) {
              ctx.shadowColor = shadowColor;
              ctx.shadowBlur = shadowBlur;
              ctx.shadowOffsetX = shadowOffset;
              ctx.shadowOffsetY = shadowOffset;
            }

            if (isGradient) {
              const gradient = ctx.createLinearGradient(tx, ty - fontSize/2, tx, ty + fontSize/2);
              gradient.addColorStop(0, color);
              gradient.addColorStop(1, color2);
              ctx.fillStyle = gradient;
            } else {
              ctx.fillStyle = color;
            }

            if (strokeWidth > 0) {
              ctx.lineWidth = strokeWidth * 2; 
              ctx.strokeStyle = strokeColor;
              ctx.strokeText(text.toUpperCase(), tx, ty);
            }

            ctx.fillText(text.toUpperCase(), tx, ty);

            if (underline) {
              let lineXStart = tx;
              if (align === 'center') lineXStart = tx - textWidth / 2;
              else if (align === 'right') lineXStart = tx - textWidth;
              const lineY = ty + fontSize * 0.45;
              ctx.beginPath();
              ctx.moveTo(lineXStart, lineY);
              ctx.lineTo(lineXStart + textWidth, lineY);
              ctx.lineWidth = fontSize * 0.08;
              ctx.strokeStyle = color;
              ctx.stroke();
            }
            ctx.restore();
        };

        drawLine(config.line1Text, config.line1Color, config.line1Color2, config.line1IsGradient, config.line1FontSize, config.line1StrokeWidth, config.line1StrokeColor, config.line1Align, config.line1Bold, config.line1Italic, config.line1Underline, config.line1ShowShadow, config.line1ShadowBlur, config.line1ShadowOffset, config.line1ShadowColor, config.line1ShowBg, config.line1BgColor, config.line1BgPaddingX, config.line1BgPaddingY, config.line1Position);
        if (config.showLine2) drawLine(config.line2Text, config.line2Color, config.line2Color2, config.line2IsGradient, config.line2FontSize, config.line2StrokeWidth, config.line2StrokeColor, config.line2Align, config.line2Bold, config.line2Italic, config.line2Underline, config.line2ShowShadow, config.line2ShadowBlur, config.line2ShadowOffset, config.line2ShadowColor, config.line2ShowBg, config.line2BgColor, config.line2BgPaddingX, config.line2BgPaddingY, config.line2Position);
        if (config.showLine3) drawLine(config.line3Text, config.line3Color, config.line3Color2, config.line3IsGradient, config.line3FontSize, config.line3StrokeWidth, config.line3StrokeColor, config.line3Align, config.line3Bold, config.line3Italic, config.line3Underline, config.line3ShowShadow, config.line3ShadowBlur, config.line3ShadowOffset, config.line3ShadowColor, config.line3ShowBg, config.line3BgColor, config.line3BgPaddingX, config.line3BgPaddingY, config.line3Position);

      const link = document.createElement('a');
      link.download = `thumbnail-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    };
    img.src = config.imageUrl || 'https://picsum.photos/1280/720?grayscale';
  };

  const getTextStyle = (line: 'line1' | 'line2' | 'line3') => {
    const c = config;
    const txtColor = c[`${line}Color` as keyof ThumbnailConfig] as string;
    const txtColor2 = c[`${line}Color2` as keyof ThumbnailConfig] as string;
    const isGrad = c[`${line}IsGradient` as keyof ThumbnailConfig] as boolean;
    const sShow = c[`${line}ShowShadow` as keyof ThumbnailConfig] as boolean;
    const sColor = c[`${line}ShadowColor` as keyof ThumbnailConfig] as string;
    const sBlur = c[`${line}ShadowBlur` as keyof ThumbnailConfig] as number;
    const sOffset = c[`${line}ShadowOffset` as keyof ThumbnailConfig] as number;
    const strokeW = c[`${line}StrokeWidth` as keyof ThumbnailConfig] as number;
    const strokeC = c[`${line}StrokeColor` as keyof ThumbnailConfig] as string;
    const align = c[`${line}Align` as keyof ThumbnailConfig] as string;
    const fSize = c[`${line}FontSize` as keyof ThumbnailConfig] as number;
    const bold = c[`${line}Bold` as keyof ThumbnailConfig] as boolean;
    const italic = c[`${line}Italic` as keyof ThumbnailConfig] as boolean;
    const underline = c[`${line}Underline` as keyof ThumbnailConfig] as boolean;
    const showBg = c[`${line}ShowBg` as keyof ThumbnailConfig] as boolean;
    const bgColor = c[`${line}BgColor` as keyof ThumbnailConfig] as string;
    const bgPadX = c[`${line}BgPaddingX` as keyof ThumbnailConfig] as number;
    const bgPadY = c[`${line}BgPaddingY` as keyof ThumbnailConfig] as number;
    const pos = c[`${line}Position` as keyof ThumbnailConfig] as {x: number, y: number};

    return {
      position: 'absolute' as const,
      left: `${pos.x}%`,
      top: `${pos.y}%`,
      transform: 'translate(-50%, -50%)',
      fontSize: `${fSize * previewScale}px`,
      WebkitTextStroke: `${strokeW * previewScale}px ${strokeC}`,
      textAlign: align as any,
      fontWeight: bold ? 'bold' : 'normal',
      fontStyle: italic ? 'italic' : 'normal',
      textDecoration: underline ? 'underline' : 'none',
      width: 'auto',
      whiteSpace: 'nowrap' as const,
      display: 'inline-block',
      lineHeight: '1.2',
      cursor: 'grab',
      zIndex: draggingLine === line ? 100 : 10,
      ...(showBg ? {
        backgroundColor: bgColor,
        padding: `${bgPadY * previewScale}px ${bgPadX * previewScale}px`,
      } : {}),
      ...(isGrad ? {
        backgroundImage: `linear-gradient(to bottom, ${txtColor}, ${txtColor2})`,
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
      } : {
        color: txtColor,
      }),
      ...(sShow ? {
        filter: `drop-shadow(${sOffset * previewScale}px ${sOffset * previewScale}px ${sBlur * previewScale}px ${sColor})`
      } : {})
    };
  };

  return (
    <div className="flex flex-col h-[100dvh] max-h-[100dvh] overflow-hidden bg-slate-950 text-slate-100">
      <header className="h-16 flex items-center justify-between px-6 border-b border-slate-800 bg-slate-900/80 backdrop-blur-md z-50">
        <div className="flex items-center gap-4">
          <div className="w-9 h-9 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
          </div>
          <span className="font-black tracking-tighter text-2xl bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">THUMBNAIL.AI</span>
          <span className="hidden sm:inline-block px-2.5 py-0.5 rounded text-[11px] bg-slate-800 text-slate-400 font-bold border border-slate-700">STUDIO PRO</span>
        </div>

        <div className="flex items-center gap-5">
          <button 
            onClick={toggleFullscreen}
            className="p-2 rounded-md text-slate-400 hover:bg-slate-800 hover:text-white transition-all"
            title={isFullscreen ? "Thoát toàn màn hình" : "Toàn màn hình (F11)"}
          >
            {isFullscreen ? (
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 9L4 4m0 0l4 4m-4-4v4m0-4h4m10 10l5 5m0 0l-5-5m5 5v-4m0 4h-4M15 9l5-5m0 0l-5 5m5-5v4m0-4h-4M9 15l-5 5m0 0l5-5m-5 5v-4m0 4h4" /></svg>
            ) : (
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5v-4m0 4h-4m4 0l-5-5" /></svg>
            )}
          </button>

          <div className="flex items-center gap-1.5 bg-slate-800/50 p-1.5 rounded-lg border border-slate-700/50">
            <button 
              onClick={undo}
              disabled={history.past.length === 0}
              className={`p-1.5 rounded-md transition-all ${history.past.length === 0 ? 'text-slate-600' : 'text-slate-200 hover:bg-slate-700 hover:text-white'}`}
              title="Undo (Ctrl+Z)"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
            </button>
            <button 
              onClick={redo}
              disabled={history.future.length === 0}
              className={`p-1.5 rounded-md transition-all ${history.future.length === 0 ? 'text-slate-600' : 'text-slate-200 hover:bg-slate-700 hover:text-white'}`}
              title="Redo (Ctrl+Y)"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 10h-10a8 8 0 00-8 8v2m18-10l-6 6m6-6l-6-6" /></svg>
            </button>
          </div>

          <button onClick={() => updateConfig(DEFAULT_CONFIG)} className="text-sm font-bold text-slate-400 hover:text-white transition-colors">RESET</button>

          <button 
            onClick={downloadThumbnail} 
            className="flex items-center gap-2.5 px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white text-sm font-black rounded-full transition-all shadow-lg shadow-indigo-500/20 active:scale-95"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
            XUẤT ẢNH
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-[330px] border-r border-slate-800 bg-slate-900/40 flex flex-col overflow-hidden">
          <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-5">
            <div className="flex items-center gap-2.5 mb-2.5">
              <span className="w-6 h-6 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-[11px] font-bold text-slate-400">2</span>
              <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Design Editor</h3>
            </div>
            <EditorControls config={config} onChange={updateConfig} />
          </div>
        </aside>

        <section className="flex-1 bg-slate-950 workspace-bg flex flex-col items-center p-8 relative overflow-y-auto custom-scrollbar">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[850px] h-[850px] bg-indigo-500/[0.03] blur-[150px] rounded-full pointer-events-none" />

          <div className="w-full max-w-[1100px] space-y-10 z-10">

            <div className="bg-slate-900/60 border border-slate-800 rounded-3xl p-7 shadow-2xl backdrop-blur-md">
              <div className="flex items-center justify-between mb-5">
                <div className="flex items-center gap-4">
                  <span className="w-7 h-7 rounded-full bg-indigo-600 flex items-center justify-center text-[12px] font-black text-white shadow-lg shadow-indigo-500/30">1</span>
                  <h3 className="text-sm font-black text-slate-300 uppercase tracking-widest">Concept Ideation</h3>
                </div>
                <div className="flex gap-2.5">
                  {['Vietnamese', 'English'].map((lang) => (
                    <button
                      key={lang}
                      onClick={() => setLanguage(lang)}
                      className={`px-3.5 py-2 rounded-lg text-[11px] font-bold transition-all border ${language === lang ? 'bg-indigo-600/10 border-indigo-500 text-indigo-400' : 'bg-slate-800/50 border-slate-700 text-slate-500'}`}
                    >
                      {lang === 'Vietnamese' ? 'Tiếng Việt' : 'English'}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex flex-col md:flex-row gap-5">
                <div className="flex-1">
                  <textarea
                    placeholder="Dán kịch bản hoặc mô tả nội dung video của bạn vào đây..."
                    className="w-full h-28 bg-slate-950/50 border border-slate-800 rounded-2xl p-5 text-base focus:ring-1 focus:ring-indigo-500 outline-none transition-all resize-none placeholder:text-slate-700"
                    value={script}
                    onChange={(e) => setScript(e.target.value)}
                  />
                </div>
                <div className="flex flex-col gap-4 min-w-[220px]">
                  <button
                    onClick={handleAnalyze}
                    disabled={status === AppStatus.ANALYZING || !script}
                    className="flex-1 py-4 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 font-black rounded-2xl transition-all shadow-xl shadow-indigo-500/10 text-sm tracking-tight flex items-center justify-center gap-2"
                  >
                    {status === AppStatus.ANALYZING ? (
                      <>
                        <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        ĐANG PHÂN TÍCH...
                      </>
                    ) : 'GỢI Ý Ý TƯỞNG'}
                  </button>
                  <button 
                    onClick={triggerUpload} 
                    className="py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all border border-slate-700 flex items-center justify-center gap-2 text-sm font-bold text-slate-300 group"
                  >
                    <svg className="w-5 h-5 text-slate-400 group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    TẢI ẢNH LÊN
                  </button>
                  <input type="file" ref={fileInputRef} onChange={handleImageUpload} className="hidden" accept="image/*" />
                </div>
              </div>
            </div>

            <div className="relative group">
              <div 
                ref={containerRef}
                className={`canvas-container w-full select-none border border-slate-800/60 overflow-hidden shadow-indigo-500/5 ${config.imageUrl ? '' : 'bg-slate-900'}`}
                style={{ backgroundImage: config.imageUrl ? `url(${config.imageUrl})` : 'none' }}
              >
                {!config.imageUrl && (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 opacity-50 pointer-events-none">
                    <svg className="w-18 h-18 mb-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <p className="text-[13px] font-black tracking-[0.35em] uppercase">Sẵn sàng thiết kế</p>
