                {config.showLine2 && (
                  <div 
                    ref={lineRefs.line2}
                    onMouseDown={(e) => handleMouseDown(e, 'line2')}
                    className={`pointer-events-auto transition-all hover:bg-white/5 p-2 rounded border border-transparent hover:border-indigo-500/20 ${draggingLine === 'line2' ? 'z-50 border-indigo-500 bg-white/10' : ''}`}
                    style={getTextStyle('line2')}
                  >
