                {config.showLine3 && (
                  <div 
                    ref={lineRefs.line3}
                    onMouseDown={(e) => handleMouseDown(e, 'line3')}
                    className={`pointer-events-auto transition-all hover:bg-white/5 p-2 rounded border border-transparent hover:border-indigo-500/20 ${draggingLine === 'line3' ? 'z-50 border-indigo-500 bg-white/10' : ''}`}
