        line3Text: words.slice(segment * 2).join(' ').toUpperCase(),
        showLine2: true, showLine3: true
      });
    } else if (words.length > 3) {
      const middle = Math.ceil(words.length / 2);
      updateConfig({
        line1Text: words.slice(0, middle).join(' ').toUpperCase(),
        line2Text: words.slice(middle).join(' ').toUpperCase(),
        showLine2: true, showLine3: false
      });
    } else {
      updateConfig({ line1Text: title.toUpperCase(), showLine2: false, showLine3: false });
    }
  };

  const handleMouseDown = (e: React.MouseEvent, line: 'line1' | 'line2' | 'line3') => {
    const ref = lineRefs[line].current;
    if (!ref || !containerRef.current) return;
    setDraggingLine(line);
    const rect = ref.getBoundingClientRect();
    setDragOffset({ x: e.clientX - (rect.left + rect.width / 2), y: e.clientY - (rect.top + rect.height / 2) });
    e.stopPropagation();
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!draggingLine || !containerRef.current) return;
